INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('d01e1278-701b-4923-86c6-9c98f7f36af6', 'Scaling Scan', 'The Scaling Scan is a practical framework developed to help teams and organizations assess the readiness and potential of agricultural innovations to scale within complex agri-food systems. It provides a structured methodology for evaluating both the innovation itself and the enabling environment in which it operates. Drawing on decades of research and field experience across sub-Saharan Africa, South Asia, and Southeast Asia, the Scaling Scan framework enables practitioners to identify critical bottlenecks, assess institutional capacity, and develop targeted strategies for scaling agricultural innovations effectively.', 'Ten-ingredient assessment framework covering technology, market, finance, policy, and institutional dimensions; Participatory scoring methodology that engages diverse stakeholders; Visual scoring dashboard for communicating bottlenecks to decision-makers; Integrated action planning module for developing targeted interventions', 'Assemble a multidisciplinary team including innovation champions, policy experts, and market specialists. Complete the pre-assessment questionnaire to gather baseline data on the innovation and its context. Conduct structured stakeholder interviews using the scoring guide for each of the ten scaling ingredients.', 'Designed for development practitioners, researchers working in agricultural development.', '{"Policy and Regulatory"}', '{"Scaling Innovation"}', 'Framework', 'Established and field-tested', '{"Government agencies",Policymaker,Researcher}', '{Africa,Asia,"Latin America"}', '{"Larry Cooley","Johannes Linn","CIMMYT Scaling Team"}', '2019-01-01', 'https://cgspace.cgiar.org/scaling-scan', 'CG Space', NULL, '[0.017456055,0.049743652,0.060577393,-0.016601562,-0.036590576,-0.0020999908,0.02935791,-0.008010864,-0.02281189,0.031280518,0.009414673,-0.061431885,-0.03543091,0.0031871796,-0.008628845,0.009567261,-0.006603241,-0.019638062,-0.01449585,0.034088135,0.04107666,0.016815186,0.0011987686,0.04852295,-0.004962921,-0.043060303,-0.026748657,0.030212402,0.01612854,-0.033355713,0.0084991455,-0.027175903,-0.06689453,0.011550903,-0.008049011,-0.021911621,-0.035095215,-0.004081726,0.0011329651,0.0013036728,0.009788513,0.031707764,-0.061279297,0.027618408,0.032928467,-0.04067993,0.016220093,-0.03765869,-0.018585205,0.03866577,-0.0051651,0.014099121,0.0004787445,-0.035369873,0.03527832,-0.009254456,-0.0104904175,0.036743164,0.00045228004,0.03591919,0.050354004,-0.0028820038,0.017868042,0.015289307,-0.0025520325,-0.0154418945,0.010482788,0.013069153,0.016677856,-0.024719238,0.014839172,0.025039673,0.013870239,-0.0014238358,0.017868042,-0.03668213,-0.02810669,0.026901245,-0.024902344,0.052124023,0.020736694,-0.042419434,-0.010414124,-0.019073486,-0.0056915283,-0.028518677,-0.031173706,-0.016143799,-0.039978027,-0.016479492,-0.004989624,0.041931152,-0.006793976,0.052459717,0.023208618,0.006706238,0.004184723,0.041229248,0.014694214,0.06072998,0.035369873,-0.026901245,0.020965576,-0.026824951,0.01461792,-0.014373779,-0.020233154,0.0105896,0.029083252,-0.016311646,-0.062316895,-0.020401001,-0.02798462,0.039123535,0.002653122,-0.08270264,-0.034576416,-0.06768799,-0.021209717,-0.016113281,-0.026947021,0.02659607,-0.03225708,0.0046920776,0.011016846,-0.054870605,-0.005256653,0.011169434,-0.0009994507,-0.009727478,-0.009109497,-0.009933472,0.03414917,-0.027740479,-0.016799927,-0.010498047,-0.07232666,-0.0041160583,-0.02482605,0.036102295,0.0034694672,0.0070762634,0.034606934,0.016815186,0.010002136,-0.017364502,-0.026901245,0.045288086,-0.023406982,0.025650024,0.011528015,-0.0008196831,-0.04711914,-0.0