INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('d1765102-7b0c-471c-bddf-f57c78811e7d', 'Agricultural Mechanization Policy Toolkit', 'The Agricultural Mechanization Policy Toolkit helps governments design and implement policies that support sustainable mechanization of smallholder farming systems, including both public sector interventions and private sector business models for mechanization service provision. The toolkit addresses the full mechanization value chain from manufacturing and import through distribution, service provision, after-sales support, and training, with specific attention to enabling environment conditions for private sector participation.', 'Mechanization demand and supply assessment methodology; Policy analysis framework for mechanization enabling environment; Business model guide for mechanization service provision; Gender-responsive mechanization design principles', 'Assess mechanization demand and supply conditions using the diagnostic tools. Analyze the policy and regulatory environment for mechanization. Identify priority policy reforms and private sector engagement opportunities.', 'Designed for policymakers, farming communities working in agricultural development.', '{"Policy and Regulatory","Market Systems"}', '{"Scaling Innovation"}', 'Tool', 'Prototype', '{Agribusiness,"Development Practitioner","Government agencies",Policymaker}', '{Africa,Asia}', '{"CIMMYT Sustainable Intensification Program","Frédéric Baudron"}', '2022-01-01', 'https://www.cimmyt.org/mechanization-policy', 'CIMMYT', NULL, '[-0.01600647,0.026855469,0.026290894,0.001953125,-0.02798462,0.025817871,0.034179688,0.05770874,0.033355713,0.046417236,0.02607727,-0.03024292,0.00482