INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('34b04e4a-0140-41e6-8bc1-267a74e9a9b4', 'MELIA Framework', 'The MELIA (Monitoring, Evaluation, Learning, and Impact Assessment) Framework provides a comprehensive system for tracking the performance and impact of agricultural research-for-development programs. It was designed to bridge the gap between accountability-focused M&E and learning-oriented approaches. MELIA integrates four interconnected functions: real-time monitoring of outputs and outcomes, periodic evaluations of program effectiveness, systematic learning processes for adaptive management, and rigorous impact assessment to measure lasting change.', 'Integrated monitoring, evaluation, learning, and impact assessment system; Theory-of-change-based results framework with outcome pathways; Participatory evaluation methods for stakeholder engagement; Digital data collection and reporting tools for real-time tracking', 'Develop a program-level theory of change with clear outcome pathways and assumptions. Design a monitoring plan with indicators aligned to the theory of change. Establish data collection protocols using the MELIA digital toolkit.', 'Designed for researchers working in agricultural development.', '{"Monitoring, Evaluation and Learning"}', '{"Scaling Innovation","Agri-food Systems"}', 'Framework', 'Established and field-tested', '{"Monitoring and Evaluation specialists",Researcher}', '{Africa,Asia,"Latin America"}', '{"CGIAR Advisory Services",ISDC}', '2018-01-01', 'https://cgspace.cgiar.org/melia', 'CG Space', NULL, '[-4.7266483e-05,0.01928711,0.023742676,0.0034294128,-0.014427185,0.022659302,0.0625,0.029144287,-0.008071899,0.035369873,0.03213501,-0.02128