INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('0f3bd7e0-2252-4129-8e1f-5eb37d1fa887', 'Gender Transformative Approach Framework', 'The Gender Transformative Approach (GTA) Framework provides a structured methodology for designing and implementing agricultural interventions that move beyond gender-sensitivity to actively address the structural causes of gender inequality within food systems. Unlike approaches that simply acknowledge gender differences, the GTA Framework equips practitioners with tools to challenge and transform the power dynamics, norms, and institutional arrangements that perpetuate gender inequality.', 'Five-level transformation framework from awareness to structural change; Gender analysis toolkit with participatory diagnostic tools; Inclusive design principles for technology and service delivery; Gender-responsive monitoring and evaluation guidance', 'Conduct a gender analysis of the innovation and target communities using participatory tools. Map existing gender norms, roles, and power dynamics relevant to the innovation. Apply the five-level framework to identify entry points for gender transformative action.', 'Designed for development practitioners, researchers working in agricultural development.', '{"Gender Equality and Social Inclusion","Policy and Regulatory"}', '{"Agri-food Systems"}', 'Framework', 'Established and field-tested', '{"Development Practitioner","Government agencies",Policymaker,Researcher}', '{Africa,Asia}', '{"Rhiannon Pyburn","Anouka van Eerdewijk","KIT Royal Tropical Institute"}', '2019-01-01', 'https://cgspace.cgiar.org/gender-transformative', 'CG Space', NULL, '[-0.032714844,0.019577026,0.03466797,-0.0060272217,-0.006259918,