INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('70771734-7a3a-433e-bb68-f18284fb1846', 'Community-Based Natural Resource Management Toolkit', 'The Community-Based Natural Resource Management (CBNRM) Toolkit provides practical guidance for establishing and strengthening community governance systems for natural resources that are critical to agricultural livelihoods, including water, grazing land, forests, and fisheries. The toolkit covers the full CBNRM process from community mobilization and resource assessment through governance design, management planning, and adaptive management. It emphasizes inclusive governance that ensures equitable participation of women and marginalized groups.', 'Community mobilization and governance design guides; Integrated resource assessment methodology combining traditional and scientific knowledge; Management planning templates for diverse natural resource types; Community-based monitoring tools with digital data collection', 'Conduct a community entry process and establish initial relationships with natural resource users. Facilitate a participatory natural resource assessment with community members. Support the community in designing inclusive governance structures for resource management.', 'Designed for farming communities working in agricultural development.', '{"Policy and Regulatory","Gender Equality and Social Inclusion"}', '{"Climate Resilience","Agri-food Systems"}', 'Tool', 'Established and field-tested', '{"Development Practitioner","Government agencies",Policymaker,"Project and program managers"}', '{Africa,Asia}', '{ILRI,ICRISAT,WorldFish}', '2018-01-01', 'https://www.ilri.org/cbnrm', 'ILRI', NULL, '[0.060394287,0.08178711,0.0