INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('cbe69ece-d449-4e92-a515-2301abf570d2', 'Market Systems Analysis', 'Market Systems Analysis (MSA) is a methodology for understanding the complex systems of actors, rules, and relationships that shape how agricultural markets function. It provides a diagnostic framework for identifying systemic constraints to market development and innovation uptake. The methodology builds on the Making Markets Work for the Poor (M4P) approach and the DCED standard for results measurement, adapted specifically for agricultural innovation contexts.', 'Core-rules-supporting functions framework for market system mapping; Value chain analysis integration for sector-specific insights; Systemic change indicators for measuring sustainable market development; Facilitation principles guide for market systems development practitioners', 'Conduct rapid market assessment to understand sector dynamics and key actors. Map the core market, rules, and supporting functions using the MSA framework. Identify systemic constraints and root causes using the constraint analysis tool.', 'Designed for farming communities working in agricultural development.', '{"Market Systems"}', '{"Agri-food Systems"}', 'Method', 'Established and field-tested', '{Agribusiness,"Development Practitioner"}', '{Africa,Asia}', '{"Springfield Centre","Alliance of Bioversity International and CIAT"}', '2016-01-01', 'https://alliancebioversityciat.org/market-systems', 'Alliance of Bioversity-CIAT', NULL, '[0.007270813,0.0513916,0.04901123,0.0012407303,-0.051239014,0.015930176,0.034210205,-0.008369446,0.029541016,0.025787354,0.031204224,-0.06689453,-0.009681702,-0.00093507767,-0.013298035,-0.