INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('93d7372e-4c5c-4354-9892-f96a70de75c8', 'Institutional Capacity Assessment', 'The Institutional Capacity Assessment (ICA) Framework provides a structured approach to evaluating the organizational systems, processes, and capabilities needed to effectively scale agricultural innovations. The ICA Framework examines seven core domains of organizational capacity: governance, strategy, human resources, financial management, program delivery, learning and adaptation, and external relations.', 'Seven-domain organizational capacity framework; Mixed-methods assessment approach combining self-assessment and external review; Organizational capacity benchmarks from high-performing institutions; Capacity development planning toolkit with prioritization tools', 'Secure organizational leadership commitment and form an assessment steering committee. Complete the self-assessment questionnaire for each of the seven capacity domains. Facilitate external review workshops with staff and key stakeholders.', 'Designed for development practitioners working in agricultural development.', '{"Policy and Regulatory","Monitoring, Evaluation and Learning"}', '{"Scaling Innovation"}', 'Framework', 'Prototype', '{"Government agencies","Monitoring and Evaluation specialists",Policymaker,Researcher}', '{Africa,Asia}', '{"CGIAR System Organization",ISDC}', '2020-01-01', 'https://cgspace.cgiar.org/institutional-capacity', 'CG Space', NULL, '[-0.006931305,0.037231445,0.054016113,0.022537231,0.002439499,-0.010116577,0.017105103,0.00089883804,-0.0033836365,-0.017105103,0.057006836,-0.056396484,-0.016921997,-0.039123535,0.046295166,-0.024307251,0.01197052,0.008346558