INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('f50f536c-f92b-4ca3-9989-44c5e1a0494d', 'Climate-Smart Policy Toolkit', 'The Climate-Smart Policy Toolkit provides governments and development organizations with practical resources for designing, evaluating, and implementing policies that support the adoption of climate-smart agricultural practices. As the impacts of climate change increasingly threaten agricultural productivity and food security, there is urgent need for policy frameworks that incentivize climate adaptation and mitigation in agriculture.', 'Climate-smart policy screening and gap analysis tool; Policy design templates for key climate-smart agriculture domains; Multi-stakeholder policy dialogue facilitation guide; Climate-smart policy monitoring and evaluation framework', 'Apply the policy screening tool to assess existing policies for climate-smart content. Identify priority policy gaps and reform opportunities using the gap analysis module. Conduct multi-stakeholder consultations using the facilitation guide.', 'Designed for development practitioners, researchers working in agricultural development.', '{"Policy and Regulatory"}', '{"Climate Resilience"}', 'Tool', 'Established and field-tested', '{"Government agencies",Policymaker,"Project and program managers"}', '{Africa,Asia,"Latin America"}', '{"FAO Climate-Smart Agriculture Unit",CCAFS}', '2018-01-01', 'https://www.fao.org/climate-smart-agriculture', 'FAO', NULL, '[-0.00074625015,-0.002527237,0.015396118,0.0009536743,-0.0069618225,0.018737793,0.004295349,0.0015563965,0.037719727,0.007789612,0.004787445,-0.056152344,0.005382538,-0.033721924,-0.013374329,-0.027557373,0.022140503,0.019607544,-0.0067634583,0