INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('3f0d698c-efb7-4600-a185-d3784fb5f3eb', 'Participatory Rural Appraisal Toolkit', 'The Participatory Rural Appraisal (PRA) Toolkit provides a comprehensive set of facilitation methods for engaging rural communities in collaborative assessment, analysis, and planning for agricultural development initiatives. PRA methods empower community members to share their knowledge, analyze their own situations, and participate meaningfully in decisions that affect their livelihoods. The toolkit includes visual, spatial, and temporal analysis methods accessible to participants regardless of literacy levels.', 'Twenty-five visual and participatory assessment methods; Digital integration tools for real-time data aggregation; Facilitation guides for diverse community contexts; Training curriculum for PRA facilitator development', 'Identify the community engagement objectives and select appropriate PRA methods. Train facilitation teams in the selected PRA methods using the training curriculum. Conduct community entry activities to build trust and explain the PRA process.', 'Designed for development practitioners, researchers working in agricultural development.', '{"Gender Equality and Social Inclusion","Policy and Regulatory"}', '{"Agri-food Systems"}', 'Method', 'Established and field-tested', '{"Development Practitioner","Government agencies",Policymaker,Researcher}', '{Asia,Africa}', '{"Robert Chambers","CGIAR Research Program on Dryland Systems"}', '2015-01-01', 'https://cgspace.cgiar.org/pra-toolkit', 'CG Space', NULL, '[-0.01423645,0.059143066,0.058288574,0.021026611,-0.02003479,0.0024757385,0.008308411,0.038604736,0.009315491,0.03240966