INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('735d3e11-e70a-42e1-8ef8-fec70e9025f7', 'ICT4Ag Assessment Framework', 'The ICT4Ag Assessment Framework provides a structured approach to evaluating how information and communication technologies can improve agricultural value chain performance, from input supply through production, processing, and marketing. The framework examines ICT readiness, demand, and supply-side factors across agricultural value chains, identifying where digital solutions can address information asymmetries, reduce transaction costs, and improve market access for smallholder farmers.', 'Value chain ICT opportunity mapping methodology; Farmer digital literacy assessment tools; ICT infrastructure and regulatory environment analysis; Business model assessment for ICT-based agricultural services', 'Select the agricultural value chain and geographic scope for assessment. Map information flows and identify ICT opportunity points along the value chain. Assess farmer digital literacy and technology access using the diagnostic tools.', 'Designed for development practitioners, researchers working in agricultural development.', '{"Digital and Financial Services","Market Systems"}', '{"Scaling Innovation"}', 'Framework', 'Prototype', '{Agribusiness,"Development Practitioner","Private sector entities",Researcher}', '{Africa,Asia,"Latin America"}', '{CTA,CABI,"CGIAR Platform for Big Data in Agriculture"}', '2020-01-01', 'https://cgspace.cgiar.org/ict4ag', 'CG Space', NULL, '[-0.034088135,-0.011657715,0.022064209,-0.0043411255,0.0006670952,0.00242424,0.054901123,-0.002696991,0.0084991455,0.04019165,0.025375366,-0.036132812,0.0038051605,-0.03111267,0.02368164,-0.03265