INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('e5d0c24e-bcda-42ef-8fe7-c6084bb76b7e', 'Seed System Development Toolkit', 'The Seed System Development Toolkit provides comprehensive guidance for strengthening national seed systems, covering the policy, regulatory, institutional, and market dimensions that determine whether farmers can access high-quality improved seed varieties. The toolkit addresses the full seed value chain from breeding and variety release through seed production, quality assurance, marketing, and farmer adoption. It includes tools for assessing seed system performance, designing reform strategies, and monitoring implementation.', 'Seed policy and regulatory assessment guide; Variety release process improvement methodology; Seed quality assurance system design templates; Commercial seed market development strategies', 'Conduct a comprehensive seed system performance assessment using the diagnostic tools. Identify priority bottlenecks in the seed value chain through stakeholder consultations. Design reform strategies for policy, quality assurance, and market development.', 'Designed for development practitioners, researchers working in agricultural development.', '{"Policy and Regulatory","Market Systems"}', '{"Agri-food Systems","Scaling Innovation"}', 'Tool', 'Established and field-tested', '{Agribusiness,"Development Practitioner","Government agencies",Policymaker}', '{Africa}', '{"Alliance of Bioversity International and CIAT","CIMMYT Seed Systems"}', '2018-01-01', 'https://alliancebioversityciat.org/seed-systems', 'Alliance of Bioversity-CIAT', NULL, '[0.0073432922,0.01335144,0.037078857,0.0015258789,-0.0395813,0.013069153,0.051757812,0.013633728,0.