INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('03227194-af6c-4714-a3c2-cc1cc0831f98', 'Theory of Change Development Guide for Agricultural Programs', 'A practical guide for developing robust theories of change for agricultural development programs. Covers stakeholder engagement, pathway mapping, assumption identification, and indicator development for results-based management.', 'Walks teams through a structured process for developing program-level theories of change, with templates and facilitation guides for each step.', 'Use during program design and inception phases to establish a clear results framework and theory of change.', 'Designed for project managers, monitoring and evaluation specialists, and program designers.', '{"Monitoring, Evaluation and Learning"}', '{"Scaling Innovation","Agri-food Systems"}', 'Guide', 'Established and field-tested', '{"Project and program managers","Monitoring and Evaluation specialists","Funders and Donors",Researcher}', '{Global}', '{"CGIAR Independent Science for Development Council"}', '2019-01-01', 'https://cgspace.cgiar.org/toc-guide', 'CGIAR ISDC', NULL, '[-0.010414124,0.005973816,0.012878418,-0.036376953,-0.052490234,-0.03668213,0.041137695,0.004673004,-0.028121948,0.030731201,0.033996582,0.018508911,-0.029144287,-0.026138306,-0.015594482,0.030334473,0.06451416,-0.0051879883,-0.01626587,0.043151855,0.016311646,0.023040771,-0.015220642,0.042022705,0.020645142,-0.03439331,-0.0116119385,0.0569458,-0.027923584,-0.013801575,0.025375366,-0.005504608,-0.021484375,-0.029937744,0.008514404,-0.049743652,0.011779785,0.0058174133,0.054504395,0.005844116,0.014854431,0.015510559,0.0063591003,0.009170532,0.0289917,0.034362793,0.018249512,0.0