INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('d2b9b722-3b88-44c3-a591-79e77586311d', 'Value Chain Analysis Toolkit', 'The Value Chain Analysis Toolkit provides a comprehensive methodology for mapping, analyzing, and upgrading agricultural value chains. It enables practitioners to understand how value is created and distributed across chain actors, identify systemic constraints, and design interventions that improve chain performance. The toolkit covers the full value chain from input supply through production, aggregation, processing, and marketing, with specific modules for analyzing governance structures, gender dynamics, and environmental sustainability within chains.', 'Full value chain mapping methodology from input supply to end market; Financial analysis tools for value distribution and profitability assessment; Gender and inclusion analysis module for equitable chain development; Upgrading strategy design framework with intervention prioritization', 'Select the value chain and geographic scope for analysis. Map chain actors, functions, and relationships using the mapping methodology. Conduct financial analysis to understand value distribution and profitability.', 'Designed for farming communities working in agricultural development.', '{"Market Systems"}', '{"Agri-food Systems"}', 'Method', 'Established and field-tested', '{Agribusiness,"Development Practitioner"}', '{Africa,Asia,"Latin America"}', '{FAO,"Alliance of Bioversity International and CIAT"}', '2016-01-01', 'https://www.fao.org/value-chain-analysis', 'FAO', NULL, '[-0.016189575,0.027389526,0.045135498,-0.01739502,-0.013534546,0.013076782,0.034606934,0.026901245,0.018234253,0.03466797,0.056671143,-0.002