INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('93109e3f-6313-4068-97d5-e3a7eecbfd97', 'Land Governance Assessment Framework', 'The Land Governance Assessment Framework (LGAF) provides a comprehensive diagnostic tool for assessing the quality of land governance across five thematic areas: legal and institutional framework, land use planning, management of public land, public provision of land information, and dispute resolution. Secure land tenure is a fundamental enabler for agricultural investment, food security, and environmental sustainability. LGAF helps countries identify weaknesses in their land governance systems and develop targeted reform strategies.', 'Five-thematic area land governance diagnostic framework; Multi-stakeholder panel assessment methodology; Standardized indicators for cross-country comparison; Policy reform prioritization matrix', 'Establish a national LGAF coordination team with government and civil society participation. Recruit and train expert panels for each of the five thematic areas. Conduct panel assessments using the standardized scoring methodology.', 'Designed for policymakers working in agricultural development.', '{"Policy and Regulatory","Gender Equality and Social Inclusion"}', '{"Agri-food Systems"}', 'Framework', 'Established and field-tested', '{"Development Practitioner","Government agencies",Policymaker,Researcher}', '{Africa,Asia,"Latin America"}', '{"World Bank Land Unit","Klaus Deininger"}', '2016-01-01', 'https://www.worldbank.org/lgaf', 'World Bank', NULL, '[0.0016756058,0.05154419,0.05218506,0.027359009,0.0019893646,0.010734558,0.009140015,-0.039031982,0.021484375,0.03149414,0.0027885437,-0.029296875,-0.009605408,-0.06683