INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('1dc20596-82c7-4002-a0a3-056cd233597b', 'Watershed Management Framework', 'The Watershed Management Framework provides guidance for planning, implementing, and monitoring integrated watershed management interventions that improve agricultural productivity while protecting natural resources and building climate resilience. The framework adopts a landscape approach, recognizing that sustainable agriculture requires management of water, soil, and biodiversity resources at the watershed scale rather than at the individual farm level.', 'Watershed characterization and mapping tools; Community-based natural resource management protocols; Soil and water conservation practice selection guide; Watershed health monitoring and evaluation system', 'Conduct a watershed characterization study using GIS tools and field assessments. Establish community watershed management committees. Develop a watershed management plan with priority interventions.', 'Designed for development practitioners, researchers working in agricultural development.', '{"Policy and Regulatory"}', '{"Climate Resilience","Agri-food Systems"}', 'Framework', 'Established and field-tested', '{"Government agencies",Policymaker,Researcher}', '{Africa,Asia,"Latin America"}', '{IWMI,"ICRISAT Watershed Program"}', '2017-01-01', 'https://www.iwmi.cgiar.org/watershed', 'IWMI', NULL, '[-0.012619019,0.06964111,0.06896973,0.010093689,-0.036468506,-0.03125,0.044433594,0.017425537,0.005241394,0.050811768,0.013298035,0.0053520203,-0.042175293,-0.035980225,0.029571533,0.024017334,0.0033397675,-0.008735657,-0.0027656555,0.031341553,0.031951904,0.03591919,-0.04336548,0.03567505,-0.00819397,