INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('b90aec0a-f9db-4c9f-af00-31d90d3bfad2', 'Rural Advisory Services Assessment', 'The Rural Advisory Services (RAS) Assessment provides a comprehensive methodology for evaluating the performance, coverage, and quality of agricultural extension and advisory service systems at national and sub-national levels. The assessment examines six dimensions: policy and institutional framework, human resources and capacity, service delivery methods, financing and sustainability, farmer satisfaction and outcomes, and pluralistic service provision.', 'Six-dimension extension system assessment framework; Farmer satisfaction and outcome measurement tools; Pluralistic service provision analysis methodology; Extension system reform prioritization guide', 'Define the scope and geographic coverage of the assessment. Assemble an assessment team with expertise in extension systems. Conduct assessments across the six dimensions using mixed methods.', 'Designed for policymakers working in agricultural development.', '{"Policy and Regulatory","Digital and Financial Services"}', '{"Scaling Innovation"}', 'Method', 'Established and field-tested', '{"Development Practitioner","Government agencies",Policymaker,"Private sector entities"}', '{Africa,Asia}', '{GFRAS,"FAO Research and Extension Unit"}', '2019-01-01', 'https://www.fao.org/rural-advisory-services', 'FAO', NULL, '[-0.0011978149,0.03302002,0.08459473,0.032958984,-0.03970337,0.014572144,0.013389587,-0.033447266,0.026931763,0.044708252,0.015533447,-0.08123779,0.0047950745,-0.040740967,0.008262634,-0.006210327,0.011878967,-0.010627747,-0.0040245056,0.040374756,0.026382446,0.01939392,0.009239197,0.01342