INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('9501bbfb-74b7-4b42-b121-e164dc7205b3', 'Social Inclusion Monitoring Toolkit', 'A practical monitoring toolkit for tracking the inclusion of marginalized groups in agricultural development programs. Provides disaggregated indicators, data collection tools, and reporting templates for gender, age, disability, and ethnicity dimensions.', 'Enables programs to systematically monitor and report on social inclusion outcomes using standardized disaggregated indicators and participatory data collection methods.', 'Integrate into program M&E systems from the design stage to ensure inclusion is tracked throughout implementation.', 'Designed for monitoring and evaluation specialists, project managers, and development practitioners.', '{"Gender Equality and Social Inclusion","Monitoring, Evaluation and Learning"}', '{"Agri-food Systems"}', 'Toolkit', 'Prototype', '{"Monitoring and Evaluation specialists","Project and program managers","Development Practitioner","Community leaders"}', '{Global,Africa}', '{"CGIAR Gender Platform","UN Women"}', '2021-01-01', 'https://cgspace.cgiar.org/social-inclusion-monitoring', 'CGIAR Gender Platform', NULL, '[0.034698486,0.026931763,0.020233154,0.014579773,-0.018051147,0.02166748,0.06616211,0.01965332,0.015533447,-0.014343262,0.012779236,-0.019302368,-0.007881165,-0.010696411,0.040374756,0.00034952164,0.0010881424,0.010757446,-0.030654907,0.07537842,0.0670166,0.076049805,-0.0020523071,0.0552063,-3.0517578e-05,-0.03665161,-0.036224365,0.038604736,-0.014076233,0.03277588,0.027160645,-0.022003174,-0.04385376,-0.012634277,0.025238037,0.009010315,-0.0070228577,0.016647339,0.026626587,0.015823364,-0.0030269623