INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('697b8df9-17f8-4e3d-b1fc-852b098b2d59', 'Food Safety Regulatory Assessment', 'The Food Safety Regulatory Assessment tool provides a structured methodology for evaluating the adequacy and effectiveness of food safety regulatory systems in developing countries, with a focus on agricultural value chains that serve domestic markets. The tool assesses five components of food safety regulation: legal framework, institutional capacity, inspection and enforcement systems, laboratory infrastructure, and stakeholder engagement mechanisms.', 'Five-component food safety regulatory assessment framework; Laboratory infrastructure assessment and benchmarking tools; Inspection system effectiveness evaluation methodology; Reform prioritization matrix for regulatory improvement', 'Identify the value chains and geographic scope for assessment. Assess each of the five regulatory components using the standardized questionnaires. Calculate the Food Safety Regulatory Index and dimension scores.', 'Designed for policymakers, farming communities working in agricultural development.', '{"Policy and Regulatory","Market Systems"}', '{"Agri-food Systems"}', 'Tool', 'Prototype', '{Agribusiness,"Development Practitioner","Government agencies",Policymaker}', '{Africa,Asia}', '{"ILRI Food Safety Program","Delia Grace"}', '2021-01-01', 'https://www.ilri.org/food-safety', 'ILRI', NULL, '[-0.031173706,0.03503418,0.03479004,0.00932312,-0.029388428,0.02671814,0.014762878,-0.020721436,0.022506714,0.04510498,0.022003174,-0.054595947,-0.021697998,-0.04486084,-0.0035171509,-0.038726807,0.02192688,-0.031433105,-0.017684937,0.031173706,0.02255249,0.012901306,-0.00678253