INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('f30cbd0b-a7ca-4c3b-8abb-b02765113c72', 'Inclusive Agribusiness Model Canvas', 'The Inclusive Agribusiness Model Canvas adapts the widely-used Business Model Canvas framework for agricultural contexts where the goal is to create commercially viable business models that integrate smallholder farmers as suppliers, employees, or customers. The canvas adds two critical dimensions to the standard business model framework: social impact pathways that ensure smallholder inclusion, and enabling environment factors that affect business model viability in agricultural development contexts.', 'Adapted Business Model Canvas with social impact and enabling environment dimensions; Smallholder integration strategy design templates; Financial viability assessment tools for inclusive business models; Impact measurement framework for inclusive agribusiness', 'Identify the agricultural value chain and target smallholder population. Map the current business model using the standard canvas elements. Add the social impact pathway and enabling environment dimensions.', 'Designed for farming communities working in agricultural development.', '{"Market Systems","Monitoring, Evaluation and Learning"}', '{"Agri-food Systems","Scaling Innovation"}', 'Method', 'Prototype', '{Agribusiness,"Development Practitioner","Monitoring and Evaluation specialists",Researcher}', '{Africa,Asia}', '{"Alliance of Bioversity International and CIAT",GIZ}', '2021-01-01', 'https://alliancebioversityciat.org/inclusive-agribusiness', 'Alliance of Bioversity-CIAT', NULL, '[0.0010690689,0.023132324,0.051757812,0.011383057,-0.0059432983,-0.0012731552,0.025344849,0.009719849,-0.0