INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('28d13f73-59b5-405d-9cd5-28e05f258b62', 'Climate Vulnerability Assessment Framework', 'The Climate Vulnerability Assessment Framework (CVAF) provides a structured methodology for assessing the vulnerability of agricultural systems to climate change, considering exposure, sensitivity, and adaptive capacity dimensions. The framework integrates climate projections with agricultural system analysis to identify which crops, livestock systems, and farming communities are most vulnerable to specific climate hazards including drought, flooding, heat stress, and changing precipitation patterns.', 'Three-dimension vulnerability assessment: exposure, sensitivity, and adaptive capacity; Climate projection integration tools for agricultural impact modeling; Vulnerability mapping and profiling methodology; Adaptation investment prioritization framework', 'Define the geographic scope and agricultural systems for assessment. Analyze climate exposure using downscaled climate projections. Assess agricultural system sensitivity to identified climate hazards.', 'Designed for funders and investors working in agricultural development.', '{"Policy and Regulatory","Monitoring, Evaluation and Learning"}', '{"Climate Resilience"}', 'Framework', 'Established and field-tested', '{"Government agencies","Monitoring and Evaluation specialists",Policymaker,Researcher}', '{Africa,Asia,"Latin America"}', '{CCAFS,"CIAT Climate Change Team"}', '2018-01-01', 'https://cgspace.cgiar.org/climate-vulnerability', 'CG Space', NULL, '[-0.050201416,0.029830933,0.0949707,0.028625488,-0.031082153,-0.014915466,0.021606445,-0.03463745,0.013961792,0.035247803,-0.012458801,-0.