INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('ef9ee66f-b8c6-4288-a681-ea25cbdc7ffb', 'Post-Harvest Loss Reduction Guide', 'The Post-Harvest Loss Reduction Guide provides comprehensive technical and institutional guidance for reducing food losses across agricultural value chains, from harvest through storage, transport, processing, and marketing. The guide covers both the technical dimensions of post-harvest loss reduction (improved storage technologies, handling practices, and processing methods) and the enabling environment requirements (policies, institutional arrangements, and market incentives) needed for sustainable loss reduction at scale.', 'Post-harvest loss assessment methodology covering all value chain stages; Technology selection guide for context-appropriate loss reduction solutions; Business model templates for commercial post-harvest service provision; Policy guidance for national food loss reduction strategies', 'Conduct a post-harvest loss assessment using the standardized methodology. Identify critical loss points and their causes across the value chain. Select appropriate loss reduction technologies using the selection guide.', 'Designed for development practitioners, researchers working in agricultural development.', '{"Market Systems","Digital and Financial Services"}', '{"Agri-food Systems"}', 'Guide', 'Established and field-tested', '{Agribusiness,"Development Practitioner","Extension services","Private sector entities"}', '{Africa,Asia}', '{"FAO Save Food Initiative","CIMMYT Post-Harvest Program"}', '2019-01-01', 'https://www.fao.org/save-food/post-harvest', 'FAO', NULL, '[-0.038848877,0.021209717,0.035827637,-0.019973755,0.0028152466,-0.017974854