INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('6ac686ec-e4a9-4d25-9cc2-619191366af1', 'Irrigation Governance Assessment', 'The Irrigation Governance Assessment provides a diagnostic framework for evaluating the governance arrangements that determine the sustainability, equity, and efficiency of irrigation systems, from small-scale farmer-managed schemes to large-scale public irrigation infrastructure. The assessment examines six governance dimensions: institutional framework, water rights and allocation, infrastructure management, financial sustainability, stakeholder participation, and environmental safeguards.', 'Six-dimension irrigation governance diagnostic framework; Multi-scale assessment from scheme to national level; Water rights and allocation analysis tools; Financial sustainability assessment for irrigation systems', 'Define the assessment scope including geographic and institutional boundaries. Assess each of the six governance dimensions using the diagnostic framework. Identify priority governance challenges and their root causes.', 'Designed for development practitioners, researchers working in agricultural development.', '{"Policy and Regulatory"}', '{"Climate Resilience","Agri-food Systems"}', 'Framework', 'Established and field-tested', '{"Government agencies",Policymaker,Researcher}', '{Asia,Africa}', '{IWMI,"FAO Land and Water Division"}', '2019-01-01', 'https://www.iwmi.cgiar.org/irrigation-governance', 'IWMI', NULL, '[0.016784668,0.032318115,0.06378174,0.009902954,-0.015586853,-0.0034694672,0.022399902,-0.037322998,0.007926941,0.03591919,0.013557434,-0.055541992,-0.029449463,-0.051696777,0.021865845,-0.0003311634,-0.024658203,-0.020141602,-0.011528015