INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('93ac91e0-da7f-4189-b41b-ed7645528c17', 'Outcome Harvesting for Agricultural Research Manual', 'A comprehensive manual for applying outcome harvesting methodology to agricultural research-for-development programs. Guides teams through identifying, formulating, verifying, and analyzing outcome statements to understand how research contributes to development changes.', 'Provides step-by-step guidance for implementing outcome harvesting in agricultural R4D contexts, including templates for outcome statements and verification protocols.', 'Apply when evaluating complex agricultural research programs where causal pathways are uncertain and outcomes emerge unpredictably.', 'Designed for monitoring and evaluation specialists and researchers working in agricultural research-for-development.', '{"Monitoring, Evaluation and Learning"}', '{"Scaling Innovation"}', 'Manual', 'Established and field-tested', '{"Monitoring and Evaluation specialists",Researcher,"Project and program managers"}', '{Global}', '{"CGIAR Advisory Services Shared Secretariat",BetterEvaluation}', '2020-01-01', 'https://cgspace.cgiar.org/outcome-harvesting-manual', 'CGIAR Advisory Services', NULL, '[0.012649536,0.04714966,0.0473938,0.0055274963,-0.052947998,-0.019714355,0.021774292,0.0062789917,0.0151901245,0.037719727,0.055114746,-0.041992188,-0.02041626,-0.043945312,0.009017944,-0.025802612,-0.003835678,-0.03692627,0.0074157715,0.036834717,0.065979004,0.018920898,-0.0006046295,0.024887085,-0.004119873,-0.04345703,-0.011375427,0.06970215,-0.0011863708,-0.062408447,-0.012008667,-0.0132751465,-0.035736084,-0.02619934,0.01071167,0.0030670166,-0.00089263916,-0.012321472,