INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('0e8f9c84-3a31-4a2b-99fe-d14cf0e27aa2', 'Gender-Inclusive Value Chains in West Africa', 'Transforming market access for women producers through policy advocacy and institutional support Transforming market access for women producers through policy advocacy and institutional support. Innovation type: Gender Transformation.', 'Women constitute over 60% of agricultural labor in West Africa but consistently capture a disproportionately small share of agricultural value chain benefits. A CGIAR-led initiative working in Ghana, Senegal, and Mali developed a comprehensive approach to creating gender-inclusive enabling environments for agricultural value chains.', 'Gender-sensitive land reform enacted in two countries, benefiting 800,000 women; Three financial service products scaled to 150,000 women users; Women''s participation in agricultural market governance increased from 18% to 45%; Income for participating women farmers increased by an average of 40%; Gender-inclusive sourcing policies adopted by 25 agricultural companies', 'Gender-inclusive value chain development requires simultaneous action at policy, institutional, and program levels. Women''s collective action organizations are critical intermediaries. Private sector commitments are more sustained when backed by certification systems. Policy reform processes are more effective when co-led by women''s organizations.', '{"Gender Equality and Social Inclusion","Market Systems","Policy and Regulatory"}', '{"Agri-food Systems"}', 'Brief', 'Established and field-tested', '{Agribusiness,"Development Practitioner","Government agencies",Policymaker}', '{Africa}', '{"IITA Gender Res