INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('d938ed49-efa8-405c-b1eb-656933d9c566', 'Integrated Pest Management Adoption Framework', 'The Integrated Pest Management (IPM) Adoption Framework provides a systems-level approach to scaling IPM practices by addressing not just the technical aspects of pest management but the enabling environment conditions needed for widespread adoption. The framework identifies four pillars of IPM scaling: farmer knowledge and capacity, market incentives for IPM-produced products, regulatory support including pesticide regulation and IPM policy, and institutional support including research-extension linkages.', 'Four-pillar IPM scaling framework: knowledge, markets, regulation, and institutions; IPM adoption barrier diagnostic methodology; Strategy design templates for scaling IPM at national level; Monitoring indicators for tracking IPM adoption and impact', 'Conduct a diagnostic assessment of IPM adoption barriers using the four-pillar framework. Identify priority barriers and their root causes through stakeholder analysis. Design a multi-pillar IPM scaling strategy addressing identified barriers.', 'Designed for development practitioners, researchers working in agricultural development.', '{"Policy and Regulatory","Market Systems"}', '{"Agri-food Systems","Climate Resilience"}', 'Framework', 'Prototype', '{Agribusiness,"Development Practitioner","Government agencies",Policymaker}', '{Asia,Africa}', '{CABI,IRRI,"CGIAR Research Program on Rice"}', '2021-01-01', 'https://cgspace.cgiar.org/ipm-adoption', 'CG Space', NULL, '[-0.0134887695,0.026306152,0.0635376,0.018692017,-0.013404846,-0.01360321,0.028442383,0.012634277,-0.023147583,0.03121948