INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('ff7e0c6a-aab2-4f2f-b4ac-f67d4bb60e84', 'Small-Scale Aquaculture Governance Guidelines', 'The Small-Scale Aquaculture Governance Guidelines provide comprehensive policy and institutional guidance for governments and development partners seeking to create enabling environments for sustainable small-scale aquaculture development. The guidelines cover seven governance areas: licensing and regulation, environmental management, access to water and land, input supply systems, market access, financial services, and research and extension for aquaculture.', 'Seven-area aquaculture governance assessment framework; Regulatory reform guidance for small-scale aquaculture; Environmental management guidelines specific to aquaculture; Market access and financial services recommendations for fish farmers', 'Assess the current governance environment for small-scale aquaculture using the framework. Identify priority governance gaps and reform opportunities. Develop policy recommendations through multi-stakeholder consultations.', 'Designed for policymakers, farming communities working in agricultural development.', '{"Policy and Regulatory","Market Systems"}', '{"Agri-food Systems"}', 'Guide', 'Prototype', '{Agribusiness,"Development Practitioner","Extension services","Government agencies"}', '{Asia,Africa}', '{WorldFish,"FAO Fisheries Division"}', '2023-01-01', 'https://www.worldfishcenter.org/governance', 'WorldFish', NULL, '[0.026412964,0.030838013,0.104003906,0.0012178421,-0.014724731,-0.018676758,0.0019426346,-0.040130615,0.0074691772,0.029586792,0.030136108,-0.056762695,-0.045776367,-0.026321411,-0.007785797,-4.2915344e-05,-0.006290436,-0