INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('86d53ad4-87ff-406c-9cff-e7049314e4d6', 'Bio-Fertilizer Scaling Approach', 'The Bio-Fertilizer Scaling Approach provides a comprehensive strategy for scaling biological soil fertility products and practices, including microbial inoculants, organic amendments, and integrated soil fertility management approaches. The approach recognizes that scaling bio-fertilizers requires simultaneous attention to quality assurance and regulation, market development, farmer awareness and training, and research-extension linkages.', 'Quality assurance system design for biological inputs; Regulatory framework analysis for bio-fertilizer registration; Market development planning tools for commercial bio-fertilizer enterprises; Farmer training curriculum for biological soil fertility management', 'Assess the current bio-fertilizer landscape including products, quality, and regulations. Analyze the regulatory framework and identify reform opportunities. Develop quality assurance systems with stakeholder participation.', 'Designed for farming communities working in agricultural development.', '{"Policy and Regulatory","Market Systems"}', '{"Agri-food Systems","Climate Resilience"}', 'Method', 'Prototype', '{Agribusiness,"Development Practitioner","Government agencies",Policymaker}', '{Africa}', '{IITA,ICRISAT,"N2Africa Program"}', '2023-01-01', 'https://www.iita.org/biofertilizer-scaling', 'IITA', NULL, '[0.038604736,0.038330078,0.061767578,0.007358551,-0.065979004,-0.008850098,0.034606934,-0.0074691772,-0.033569336,0.053253174,0.059020996,-0.035064697,-0.049224854,-0.011047363,0.021316528,-0.007534027,0.010261536,-0.008361816,-0.016998291,-0.021362