INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('6dd49b3a-099c-40cc-a8fd-0863577ac1f1', 'Digital Extension Services in South Asia', 'Leveraging mobile platforms to deliver agricultural advisory services to remote communities Leveraging mobile platforms to deliver agricultural advisory services to remote farming communities. Innovation type: Digital Innovation.', 'Across the Indo-Gangetic Plain, millions of smallholder farmers have historically lacked reliable access to agricultural extension services. Building on the rapid growth of mobile connectivity across rural South Asia, a multi-country initiative launched an ambitious program to create enabling environments for digital extension services.', '5 million farming households reached with digital extension services; 28% higher adoption rates for recommended agricultural practices; 12 private sector partners catalyzed to invest in digital agriculture; National digital agriculture policies enacted in three countries; Data governance frameworks established for agricultural data sharing', 'Digital extension services require a supportive policy environment, not just technology. Sustainable business models for digital extension must be designed from the start. Digital literacy investments are as important as connectivity infrastructure. Gender-inclusive design significantly increases women''s participation in digital services.', '{"Digital and Financial Services","Policy and Regulatory"}', '{"Scaling Innovation","Agri-food Systems"}', 'Brief', 'Established and field-tested', '{"Development Practitioner","Government agencies",Policymaker,"Private sector entities"}', '{Asia}', '{"IRRI Digital Innovation Team","CIMMYT South Asia"}'