INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('9cdf976a-5600-4b3d-aeb7-167bf1c08c25', 'Climate Adaptation in the Sahel', 'Building enabling environments for climate-resilient agriculture through multi-stakeholder governance Building enabling environments for climate-resilient agriculture through multi-stakeholder governance. Innovation type: Climate Governance.', 'The Sahel region faces some of the most severe climate impacts on agriculture in the world. A CGIAR initiative working across six Sahelian countries took a systems approach to strengthening enabling environments for climate adaptation in agriculture.', 'National climate-smart agriculture strategies adopted in all six countries; Regional climate early warning system serving 3 million farming households; Multi-stakeholder governance platforms operational in six countries; 40% increase in climate adaptation investment across the region; 500,000 farmers trained in climate-smart agricultural practices', 'Regional coordination mechanisms are essential for cross-boundary climate challenges. Multi-stakeholder platforms need clear mandates and adequate resourcing. Climate adaptation reforms must be linked to technical assistance programs. Pastoralists require specific policy and institutional recognition.', '{"Policy and Regulatory"}', '{"Climate Resilience","Agri-food Systems"}', 'Brief', 'Established and field-tested', '{"Government agencies",Policymaker}', '{Africa}', '{"CCAFS West Africa","ICRISAT Sahel Program"}', '2022-01-01', '', 'CG Space', NULL, '[0.042297363,0.0037117004,0.09753418,0.036010742,-0.033203125,0.015716553,0.028839111,0.03881836,-0.017608643,0.034942627,-0.009628296,-0.06137085,-0.03286743,-0.038085