INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('449f3793-4d2d-46e1-8ac2-a79e5dbcf71e', 'Agricultural Finance Innovation in Southeast Asia', 'Creating regulatory frameworks that enable fintech solutions for smallholder agricultural lending Creating regulatory frameworks that enable fintech solutions for smallholder agricultural lending. Innovation type: Financial Innovation.', 'Access to finance remains one of the most significant barriers to agricultural innovation adoption among smallholder farmers in Southeast Asia. A CGIAR initiative working with governments and financial regulators in Indonesia, Philippines, and Vietnam developed enabling environments for agricultural fintech.', 'Regulatory sandboxes for agricultural fintech established in two countries; Agricultural data-sharing frameworks adopted by three governments; 8 fintech companies launched agricultural loan products reaching 500,000 farmers; Satellite-indexed agricultural insurance scaled to 300,000 farmers; Average agricultural loan processing time reduced from 3 weeks to 48 hours', 'Regulatory sandboxes are powerful tools for enabling fintech innovation while managing risk. Agricultural data-sharing frameworks that protect farmer privacy are foundational. Consumer protection frameworks must be developed proactively. Agricultural insurance is a critical complement to agricultural lending.', '{"Monitoring, Evaluation and Learning","Digital and Financial Services","Policy and Regulatory"}', '{"Scaling Innovation","Agri-food Systems"}', 'Brief', 'Established and field-tested', '{"Development Practitioner","Government agencies","Monitoring and Evaluation specialists",Policymaker}', '{Asia}', '{"World Bank Agricul