INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('9ce4e158-b536-4c00-b23b-5cd95ba19723', 'Post-Harvest Technology Adoption in Sub-Saharan Africa', 'Scaling hermetic storage technologies to reduce grain losses for millions of smallholder farmers Scaling hermetic storage technologies to reduce grain losses for millions of smallholder farmers. Innovation type: Technology Scaling.', 'Post-harvest grain losses in Sub-Saharan Africa average 20-30%, costing farmers billions of dollars annually and undermining food security. A CIMMYT-led initiative worked to scale hermetic storage technologies across five East African countries by creating the enabling environment conditions for private sector-led technology distribution.', '3 million hermetic storage bags distributed across five countries; Average 80% reduction in grain storage losses for adopting farmers; Private sector distribution networks established in all five countries; Quality standards adopted for hermetic storage technologies; Farmer incomes increased by 15-25% through reduced losses', 'Enabling environment reforms can catalyze private sector investment in technology distribution. Quality standards are essential for building farmer trust in new technologies. Extension programs must reach women who are often responsible for post-harvest management. Regulatory harmonization across countries enables economies of scale.', '{"Market Systems","Policy and Regulatory"}', '{"Agri-food Systems","Scaling Innovation"}', 'Brief', 'Established and field-tested', '{Agribusiness,"Development Practitioner","Government agencies",Policymaker}', '{Africa}', '{"CIMMYT Post-Harvest Program","Hugo De Groote"}', '2025-01-01', '', 'CIMMYT', NULL,