INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('5f1f85cc-a27d-4257-9365-119ead224ade', 'Digital Market Access in Latin America', 'Connecting smallholder farmers to urban markets through digital platforms and policy support Connecting smallholder farmers to urban markets through digital platforms and policy support. Innovation type: Digital Market Innovation.', 'Smallholder farmers in Latin America often face significant barriers to accessing urban markets, including high transaction costs, poor market information, and limited negotiating power. The Alliance of Bioversity-CIAT developed a digital market platform initiative in Colombia, Guatemala, and Peru that combined technology development with enabling environment reforms.', '50,000 smallholder farmers connected to urban markets through digital platforms; Average farmer income increase of 30% through improved market access; Regulatory frameworks for digital agricultural markets established in three countries; Product traceability systems implemented for six value chains; Digital literacy programs reached 25,000 farming households', 'Digital platforms need enabling regulatory frameworks to operate at scale. Product quality and traceability standards build consumer trust and willingness to pay. Digital literacy programs are essential for smallholder participation. Public-private partnerships can drive sustainable platform development.', '{"Digital and Financial Services","Market Systems"}', '{"Agri-food Systems","Scaling Innovation"}', 'Brief', 'Established and field-tested', '{Agribusiness,"Development Practitioner","Private sector entities"}', '{"Latin America"}', '{"Alliance of Bioversity-CIAT Digital Innovation","Mark 