INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('8d33debe-03df-4b7d-a621-0b32090d87e7', 'Mechanization Policy in Southern Africa', 'Designing policies that enable sustainable agricultural mechanization for smallholder farming systems Designing policies that enable sustainable agricultural mechanization for smallholder farming systems. Innovation type: Policy Innovation.', 'Agricultural mechanization in Southern Africa has lagged behind other regions, with most smallholder farmers relying on manual labor that limits productivity and increases drudgery. CIMMYT led an initiative to design and implement mechanization policies in Zambia, Tanzania, and Ethiopia that created enabling conditions for private sector mechanization service provision.', '200,000 farming households served by private mechanization service providers; 40% increase in agricultural labor productivity in target areas; Import duties on agricultural machinery reduced in two countries; 500 mechanization service providers trained and operational; Gender-responsive mechanization designs adopted for three crop systems', 'Private sector mechanization service provision is more sustainable than government programs. Import duty reforms can significantly reduce the cost of mechanization. Gender-responsive mechanization design increases women''s access to labor-saving technologies. Training and after-sales support are as important as machinery supply.', '{"Policy and Regulatory","Market Systems"}', '{"Scaling Innovation"}', 'Brief', 'Established and field-tested', '{Agribusiness,"Development Practitioner","Government agencies",Policymaker}', '{Africa}', '{"CIMMYT Sustainable Intensification","Frederic Baudron"}', '2025-01