INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('af491e45-89ce-468d-9ef2-bdb392f2bbdd', 'Nutrition-Sensitive Agriculture in Bangladesh', 'Integrating nutrition objectives into agricultural policy and programming Integrating nutrition objectives into agricultural policy and programming for improved dietary outcomes. Innovation type: Policy Integration.', 'Despite significant progress in food production, Bangladesh continues to face high rates of malnutrition, particularly among women and children in rural areas. A multi-partner initiative led by IFPRI and WorldFish worked to create enabling environments for nutrition-sensitive agriculture in Bangladesh, focusing on policy reform, institutional capacity building, and program design.', 'Nutrition objectives integrated into national agricultural policy framework; Dietary diversity scores improved by 20% in target areas; 5,000 agricultural extension workers trained in nutrition messaging; Food safety regulatory system strengthened with new standards; Three nutrition-sensitive agricultural programs reaching 500,000 households', 'Integrating nutrition into agriculture requires cross-ministerial coordination. Extension worker training in nutrition is a cost-effective pathway to scale. Women''s empowerment programs amplify the nutrition impacts of agricultural interventions. Food safety improvements complement nutrition-sensitive agricultural approaches.', '{"Policy and Regulatory","Gender Equality and Social Inclusion"}', '{"Agri-food Systems"}', 'Brief', 'Established and field-tested', '{"Development Practitioner","Government agencies",Policymaker,Researcher}', '{Asia}', '{"IFPRI Bangladesh","WorldFish Bangladesh",A4NH}', '2024-01