INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('a476ffc5-4844-4127-b0c4-13121608dd57', 'Women''s Empowerment in Agriculture Index (WEAI) Toolkit', 'A survey-based toolkit for measuring the empowerment, agency, and inclusion of women in the agricultural sector. Covers five domains of empowerment including decisions about agricultural production, access to resources, control of income, leadership, and time allocation.', 'Measures five domains of women''s empowerment in agriculture through standardized survey instruments and provides an aggregate empowerment score for benchmarking and tracking progress.', 'Use during project baseline and endline to measure changes in women''s empowerment resulting from agricultural interventions.', 'Designed for researchers, development practitioners, and monitoring and evaluation specialists.', '{"Gender Equality and Social Inclusion"}', '{"Agri-food Systems"}', 'Scale', 'Established and field-tested', '{Researcher,"Development Practitioner","Monitoring and Evaluation specialists"}', '{Global,Asia,Africa}', '{IFPRI,"USAID Feed the Future"}', '2019-01-01', 'https://cgspace.cgiar.org/weai-toolkit', 'IFPRI', NULL, '[0.017211914,0.016143799,0.0592041,0.01977539,-0.02558899,0.0034809113,0.032318115,0.030731201,0.020370483,0.03265381,0.014503479,-0.00178051,-0.03942871,-0.087646484,0.026809692,0.017333984,0.030654907,-0.00687027,-0.034484863,0.035339355,0.011474609,0.01776123,-0.029006958,0.015457153,-0.017547607,-0.014556885,-0.022277832,0.0149383545,-0.025421143,-0.009628296,-0.010391235,-0.013465881,-0.017425537,-0.02192688,0.010498047,0.016906738,0.023834229,-0.005355835,0.05886841,-0.017105103,0.016357422,0.033081055,-0.035888672,-0.01159668,