INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('d932ce67-b810-448f-b7b8-ad0cc330ee64', 'Adaptive Management Toolkit for Agricultural Programs', 'A toolkit for implementing adaptive management approaches in agricultural development programs. Provides tools for real-time monitoring, rapid learning cycles, and evidence-based decision-making to improve program effectiveness in complex and uncertain environments.', 'Enables programs to implement pause-and-reflect cycles, rapid evidence reviews, and structured decision-making processes for adaptive program management.', 'Use throughout program implementation to enable evidence-based course corrections and improve program effectiveness.', 'Designed for project managers and development practitioners managing complex agricultural programs.', '{"Monitoring, Evaluation and Learning"}', '{"Scaling Innovation"}', 'Toolkit', 'Prototype', '{"Project and program managers","Development Practitioner","Monitoring and Evaluation specialists"}', '{Global,Africa,Asia}', '{"USAID Learning Lab","Mercy Corps AgriFin"}', '2021-01-01', 'https://cgspace.cgiar.org/adaptive-management-toolkit', 'USAID', NULL, '[-0.0025596619,0.032409668,0.028503418,0.0070114136,-0.006477356,0.02571106,0.024902344,0.030517578,0.014526367,0.04647827,0.041931152,-0.04827881,-0.014945984,-0.047912598,0.017868042,-0.031555176,0.019638062,-0.008911133,-0.022918701,0.05303955,0.015106201,0.01499176,0.003074646,0.036346436,0.015037537,-0.038391113,-0.04598999,0.023284912,-0.007827759,-0.016311646,0.037139893,-0.024353027,-0.047210693,0.01574707,-0.0001103282,0.016281128,0.007572174,0.012023926,0.03250122,0.011947632,-0.007507324,-0.013061523,-0.002981186,0.021987915,-0.0408020