INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('6f55fa0d-a963-4ae0-a1c0-ae53903be867', 'Mobile Agricultural Advisory Services Design Manual', 'A design manual for developing mobile phone-based agricultural advisory services that reach smallholder farmers with timely agronomic advice, market information, and weather alerts. Covers service design, content development, delivery channels, and sustainability models.', 'Guides the design and implementation of mobile advisory services including IVR, SMS, and app-based platforms for agricultural extension.', 'Use when planning or redesigning digital agricultural advisory services for smallholder farmer audiences.', 'Designed for development practitioners, private sector entities, and extension services deploying digital agriculture solutions.', '{"Digital and Financial Services"}', '{"Scaling Innovation"}', 'Manual', 'Established and field-tested', '{"Development Practitioner","Private sector entities","Extension services","Farmers and Agro-pastoralists"}', '{Africa,Asia}', '{"GSMA AgriTech Programme",CTA}', '2020-01-01', 'https://cgspace.cgiar.org/mobile-advisory-manual', 'GSMA', NULL, '[0.009613037,0.04144287,0.056732178,-0.027404785,-0.05834961,-0.012077332,0.044311523,-0.020980835,0.037200928,0.05166626,-0.0102005005,-0.05545044,-0.0033950806,-0.0335083,0.0050849915,-0.0035419464,0.0096588135,-0.004219055,-0.012641907,0.022827148,0.057678223,0.07733154,0.018692017,0.0031261444,-0.01751709,-0.028533936,-0.037322998,0.02960205,-0.0032863617,-0.08325195,0.017532349,-0.021743774,-0.013137817,-0.023086548,-0.011436462,-0.0027332306,0.033203125,0.004749298,0.042266846,0.014427185,-0.011650085,-0.02017212,0.031829834,0.007873535,-0.0