INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('4e2fd2ef-3cfe-4ca9-942e-f62d93a1b1fc', 'Agricultural Data Governance Framework', 'A framework for establishing governance arrangements for agricultural data collection, sharing, and use. Addresses data ownership, privacy, consent, and interoperability in the context of digital agriculture platforms and open data initiatives.', 'Provides principles and practical guidance for governing agricultural data ecosystems, including templates for data sharing agreements and privacy impact assessments.', 'Apply when establishing data governance for agricultural data platforms, open data initiatives, or cross-organizational data sharing arrangements.', 'Designed for policymakers, technology developers, and research organizations managing agricultural data.', '{"Digital and Financial Services","Policy and Regulatory"}', '{"Agri-food Systems"}', 'Framework', 'Conceptual', '{Policymaker,Researcher,"Private sector entities","Government agencies"}', '{Global,Africa}', '{"CGIAR Platform for Big Data in Agriculture",GODAN}', '2023-01-01', 'https://cgspace.cgiar.org/data-governance', 'CGIAR Big Data Platform', NULL, '[0.0032463074,0.02470398,0.049438477,0.0043792725,0.0023899078,-0.0018796921,0.015319824,-0.012275696,-0.010681152,0.02772522,0.025726318,-0.03604126,-0.027618408,-0.045776367,-0.020446777,-0.018585205,0.021408081,-0.0028686523,0.037078857,0.066833496,0.018966675,0.03353882,-0.009635925,0.028823853,-0.04611206,-0.043273926,0.0060272217,0.015235901,-0.026641846,-0.037963867,-0.018249512,-0.012870789,-0.00680542,-0.021209717,0.019012451,-0.007686615,-0.011360168,0.005970001,0.003929138,0.03527832,0.012924194,-0.026245117,-0.015136719,