INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('bee40b2a-ef81-487d-883a-49ace64dc77f', 'Regulatory Impact Assessment for Agriculture', 'A method for systematically assessing the potential impacts of proposed agricultural regulations on farmers, agribusinesses, consumers, and the environment. Integrates cost-benefit analysis with stakeholder consultation to improve regulatory quality.', 'Guides regulatory bodies through a structured impact assessment process including problem definition, option analysis, cost-benefit estimation, and stakeholder consultation.', 'Apply before enacting new agricultural regulations or reforming existing ones to ensure evidence-based policymaking.', 'Designed for policymakers, government agencies, and researchers supporting agricultural policy reform.', '{"Policy and Regulatory"}', '{"Agri-food Systems"}', 'Method', 'Established and field-tested', '{Policymaker,"Government agencies",Researcher}', '{Global,Africa,Asia}', '{"IFPRI Governance Division","OECD Agriculture Directorate"}', '2019-01-01', 'https://cgspace.cgiar.org/regulatory-impact-assessment', 'IFPRI', NULL, '[0.0013904572,0.04034424,0.027526855,0.03378296,-0.051483154,0.022460938,0.0021476746,-0.022247314,0.016937256,0.06188965,0.03161621,-0.030578613,-0.025024414,-0.01550293,-0.033691406,-0.036376953,0.006500244,-0.025909424,-0.015579224,0.040405273,0.020431519,0.031402588,-0.009605408,-0.0019798279,0.011695862,-0.070739746,0.0022602081,-0.015464783,-0.019363403,-0.028778076,0.04333496,-0.0036029816,-0.01826477,-0.051513672,-6.997585e-05,-0.0042686462,-0.0060424805,-0.029281616,0.04232788,0.046020508,0.030960083,0.040283203,0.010505676,0.01689148,-0.033294678,0.01524353,-0.019180298,