INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('cfeacdc8-fae8-4279-b4a4-794470b5192d', 'Climate-Smart Agriculture Prioritization Framework', 'A framework for prioritizing climate-smart agriculture (CSA) practices based on their potential for productivity improvement, adaptation, and mitigation in specific agro-ecological and socioeconomic contexts. Uses multi-criteria analysis to rank CSA options.', 'Enables systematic comparison and prioritization of CSA practices using multi-criteria analysis across productivity, adaptation, and mitigation dimensions.', 'Use when selecting CSA practices for promotion in national or sub-national agricultural development programs.', 'Designed for policymakers, researchers, and extension services planning climate-smart agriculture programs.', '{"Policy and Regulatory"}', '{"Climate Resilience","Agri-food Systems"}', 'Framework', 'Established and field-tested', '{Policymaker,Researcher,"Extension services","Government agencies"}', '{Global,Africa,Asia}', '{CCAFS,"World Bank Climate-Smart Agriculture Team"}', '2017-01-01', 'https://cgspace.cgiar.org/csa-prioritization', 'CCAFS', NULL, '[0.0104904175,-0.0035057068,0.05429077,-0.012329102,-0.015129089,-0.01348114,0.039978027,0.007827759,0.019180298,0.03845215,0.015640259,-0.047454834,-0.034576416,-0.0009007454,0.024963379,-0.02960205,0.012359619,-0.047088623,0.018493652,0.0047912598,-0.007091522,0.026321411,-0.020309448,0.06542969,-0.010696411,-0.04901123,0.028945923,0.0030517578,0.003932953,-0.015899658,0.0287323,-0.02053833,-0.014984131,-0.012580872,-0.014282227,-0.058166504,-0.028915405,0.020065308,0.013893127,0.017852783,-0.020004272,0.028518677,-0.04498291,-0.023620605,0.01235199,-6.258487