INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('ed50dbcd-89a5-4fc9-b4c3-7b4c958a2190', 'Drought Resilience Assessment Tool', 'A diagnostic tool for assessing household and community-level drought resilience in semi-arid agricultural systems. Measures resilience capacities across absorptive, adaptive, and transformative dimensions to inform drought preparedness programming.', 'Assesses drought resilience at household and community levels across three capacity dimensions and generates resilience profiles for targeting interventions.', 'Use when designing drought preparedness programs or assessing the impact of resilience-building interventions in dryland farming systems.', 'Designed for humanitarian assistance practitioners, development practitioners, and government agencies in drought-prone regions.', '{"Policy and Regulatory","Gender Equality and Social Inclusion"}', '{"Climate Resilience"}', 'Tool', 'Prototype', '{"Humanitarian assistance practitioners","Development Practitioner","Government agencies","Local communities"}', '{Africa,MENA,"Central and West Asia and North Africa (CWANA)"}', '{"ICRISAT Resilience Program","ILRI Dryland Systems"}', '2021-01-01', 'https://cgspace.cgiar.org/drought-resilience-tool', 'ICRISAT', NULL, '[-0.0023403168,0.04196167,0.049804688,0.016998291,-0.0259552,-0.007045746,0.004245758,0.035461426,0.002828598,0.039489746,-0.049957275,-0.03918457,0.021697998,-0.0574646,0.03326416,-0.0066375732,0.040802002,-0.018112183,-0.03137207,0.062683105,0.02734375,-0.011871338,-0.02998352,-0.026748657,0.03152466,-0.016281128,-0.025146484,0.03967285,0.019241333,-0.045318604,-0.01612854,-0.025405884,-0.02822876,-0.02708435,0.014053345,0.01033783,0.00043988228,