INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('9c5e1f48-3816-45b2-a6c1-70f4a0a1a6f2', 'Greenhouse Gas Emissions Estimation Guide for Agriculture', 'A practical guide for estimating greenhouse gas emissions from agricultural activities including crop production, livestock, and land use change. Provides Tier 1 and Tier 2 estimation methods aligned with IPCC guidelines for national GHG inventories.', 'Provides calculation methods and emission factors for estimating GHG emissions from agriculture, with Excel-based calculation tools and data collection protocols.', 'Use when developing national GHG inventories, designing climate finance proposals, or estimating the mitigation potential of agricultural interventions.', 'Designed for government agencies responsible for GHG reporting, researchers, and climate finance practitioners.', '{"Monitoring, Evaluation and Learning","Policy and Regulatory"}', '{"Climate Resilience"}', 'Guide', 'Established and field-tested', '{"Government agencies",Researcher,Policymaker,"Monitoring and Evaluation specialists"}', '{Global,Africa,"Latin America"}', '{CCAFS,"FAO Climate Change Division"}', '2019-01-01', 'https://cgspace.cgiar.org/ghg-estimation-guide', 'FAO', NULL, '[-0.0003373623,0.017410278,0.045166016,-0.012939453,-0.04522705,-0.024230957,0.0041923523,0.01977539,0.018615723,0.0026226044,0.03036499,0.035888672,-0.013870239,-0.013969421,-0.024246216,-0.011627197,0.0013456345,-0.018447876,-0.025527954,0.07672119,-0.019607544,0.02027893,0.017868042,0.04232788,-0.023910522,-0.03555298,-0.007827759,0.00070667267,0.0028438568,-0.02796936,0.036254883,-0.008285522,0.031402588,-0.060272217,0.04852295,-0.033355713,-0.016403198,0.0041618347,0.0113525