INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('5c60468e-80ba-4d50-9399-45dcdabf19aa', 'Water-Energy-Food Nexus Assessment for MENA', 'An assessment framework for analyzing water-energy-food nexus dynamics in water-scarce MENA region contexts. Integrates quantitative modeling with stakeholder analysis to identify nexus trade-offs and synergies for policy coherence.', 'Provides an integrated assessment methodology for understanding WEF nexus interactions and developing coherent policy recommendations for water-scarce agricultural systems.', 'Use when developing integrated water-energy-food policies or assessing the cross-sector impacts of agricultural investments in water-scarce regions.', 'Designed for policymakers, researchers, and government agencies in water-scarce agricultural regions.', '{"Policy and Regulatory"}', '{"Climate Resilience","Agri-food Systems"}', 'Framework', 'Theoretical and diagnostics', '{Policymaker,Researcher,"Government agencies","Irrigation scheme managers"}', '{MENA,"Central and West Asia and North Africa (CWANA)"}', '{"IWMI MENA Programme",ICARDA}', '2022-01-01', 'https://cgspace.cgiar.org/wef-nexus-mena', 'IWMI', NULL, '[-0.045654297,0.04034424,0.04171753,-0.007499695,-0.007270813,0.033172607,0.026168823,0.030151367,0.030944824,0.043762207,0.00881958,-0.021118164,-0.05529785,-0.05429077,0.008483887,0.054504395,-0.0029888153,-0.0390625,-0.0054512024,0.01878357,0.019943237,0.027938843,-0.016571045,0.023544312,0.003490448,-0.013420105,-0.0011777878,0.04650879,-0.004951477,-0.0018625259,0.041870117,-0.015106201,-0.027252197,-0.04171753,-0.012245178,0.030319214,0.029067993,0.02192688,0.018081665,0.02293396,-0.013748169,0.05908203,-0.029953003,0.0415