INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('60244636-2ab9-4751-b6ef-9e3b2f093285', 'Dryland Agriculture Transformation Guide', 'A guide for transforming dryland agricultural systems in arid and semi-arid regions through integrated approaches combining improved germplasm, water harvesting, conservation agriculture, and market linkages. Draws on evidence from North Africa and Central Asia.', 'Provides an integrated package of technical options and institutional arrangements for sustainably intensifying dryland farming systems.', 'Use when designing agricultural development programs in semi-arid and arid regions with limited water resources.', 'Designed for development practitioners, extension services, and researchers working in dryland farming systems.', '{"Market Systems","Policy and Regulatory"}', '{"Climate Resilience","Agri-food Systems"}', 'Guide', 'Established and field-tested', '{"Development Practitioner","Extension services",Researcher,"Farmers and Agro-pastoralists"}', '{MENA,"Central and West Asia and North Africa (CWANA)",Africa}', '{ICARDA,"ICRISAT Dryland Systems"}', '2018-01-01', 'https://cgspace.cgiar.org/dryland-transformation', 'ICARDA', NULL, '[-0.019470215,0.029830933,0.04660034,0.001540184,-0.05178833,-0.03994751,0.04714966,0.013183594,-0.01398468,0.05130005,-0.004825592,-0.0074043274,-0.010902405,-0.050231934,0.011749268,0.04751587,0.018661499,-0.0008711815,-0.009223938,0.034484863,0.012664795,0.037353516,-0.02027893,0.014259338,0.0064315796,-0.018051147,-0.018936157,0.07684326,-0.014289856,-0.026672363,0.013313293,-0.014831543,-0.017166138,-0.044433594,0.02709961,-0.015640259,0.011192322,0.032043457,0.017105103,0.034240723,-0.0077705383,-0.0027370