INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('38500a22-9e74-4dd5-9f19-19d3593b65ee', 'Saline Agriculture Adaptation Framework', 'A framework for adapting agricultural systems to increasing soil and water salinity in coastal and irrigated areas. Covers salt-tolerant crop selection, soil management practices, irrigation management, and institutional support for farmers dealing with salinity challenges.', 'Provides an integrated approach for managing agricultural salinity including crop selection tools, soil amendment guidelines, and irrigation management protocols.', 'Use when addressing salinity challenges in coastal deltas, irrigated areas, or regions affected by rising groundwater salinity.', 'Designed for extension services, irrigation scheme managers, and researchers working on salinity management.', '{"Policy and Regulatory"}', '{"Climate Resilience","Agri-food Systems"}', 'Framework', 'Theoretical and diagnostics', '{"Extension services","Irrigation scheme managers",Researcher,"Farmers and Agro-pastoralists"}', '{MENA,Asia,"Central and West Asia and North Africa (CWANA)"}', '{ICBA,"ICARDA Water and Land Management"}', '2021-01-01', 'https://cgspace.cgiar.org/saline-agriculture', 'ICBA', NULL, '[0.009613037,0.03463745,0.07409668,0.022521973,-0.0231781,-0.019714355,0.030288696,-0.034729004,-0.024719238,0.041046143,-0.01776123,-0.06542969,0.0042381287,0.007801056,0.007987976,-0.012580872,0.03253174,-0.02368164,-0.0054893494,0.03652954,0.03842163,0.0065574646,0.005256653,0.013961792,0.036254883,-0.0592041,0.019226074,0.06707764,-0.044647217,-0.051849365,0.04675293,-0.018203735,-0.014564514,-0.011352539,0.013710022,0.01234436,0.012367249,0.01436615,-0.039642334,0.0139999