INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('856275c7-5364-47c2-99c5-78a0e7d528e3', 'European Agricultural Knowledge Transfer Matrix', 'A matrix tool for evaluating and comparing the effectiveness of different knowledge transfer mechanisms used in European agricultural advisory systems. Assesses mechanisms including demonstrations, farmer groups, digital platforms, and peer-to-peer learning.', 'Provides a structured comparison matrix for evaluating knowledge transfer approaches across effectiveness, reach, cost-efficiency, and inclusiveness criteria.', 'Use when designing or reforming agricultural knowledge transfer programs and selecting the most appropriate mechanisms for different contexts.', 'Designed for extension services, policymakers, and researchers working on agricultural advisory systems.', '{"Policy and Regulatory","Digital and Financial Services"}', '{"Scaling Innovation"}', 'Matrix', 'Prototype', '{"Extension services",Policymaker,Researcher,"Government agencies"}', '{Europe,Global}', '{"EU AKIS Network","FAO Knowledge Management Division"}', '2021-01-01', 'https://cgspace.cgiar.org/knowledge-transfer-matrix', 'EU AKIS Network', NULL, '[-0.041534424,0.028915405,0.007583618,-0.009460449,-0.009315491,0.034362793,0.035736084,0.008148193,0.017044067,0.05758667,0.031280518,-0.04547119,0.006416321,-0.030944824,0.030853271,-0.034729004,0.016525269,-0.030670166,-0.010673523,0.043762207,0.018478394,-0.00083875656,0.01335144,0.051330566,0.015289307,-0.064208984,-0.008125305,0.0007381439,-0.04257202,0.019638062,0.011680603,-0.018493652,-0.00065660477,0.0070381165,0.014343262,-0.0046806335,-0.00080394745,0.043548584,0.012931824,0.030807495,0.025924683,0.040863037,-0.0