INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('7318207a-9200-4de1-b83e-11d97a128778', 'Indigenous Knowledge Integration Toolkit', 'A toolkit for integrating indigenous and traditional ecological knowledge into agricultural research and development programs in Latin American contexts. Provides ethical protocols, participatory methods, and documentation standards for respectful knowledge integration.', 'Provides ethical frameworks and participatory methods for documenting, validating, and integrating indigenous agricultural knowledge into research and extension programs.', 'Use when working with indigenous communities on agricultural development projects or when seeking to integrate traditional knowledge into modern agricultural practices.', 'Designed for researchers, development practitioners, and community leaders working with indigenous agricultural communities.', '{"Gender Equality and Social Inclusion","Policy and Regulatory"}', '{"Agri-food Systems"}', 'Toolkit', 'Prototype', '{Researcher,"Development Practitioner","Community leaders","Local communities"}', '{"Latin America",Asia,Africa}', '{"Bioversity International",CATIE}', '2020-01-01', 'https://cgspace.cgiar.org/indigenous-knowledge-toolkit', 'Bioversity International', NULL, '[-0.01701355,0.015640259,0.009414673,0.011184692,-0.027359009,-0.011436462,0.0390625,0.043640137,-0.003824234,0.016067505,0.003829956,-0.015510559,0.005531311,-0.05593872,0.048034668,-0.0033473969,-0.007980347,0.003917694,-0.041137695,0.062805176,0.04083252,0.010238647,-0.025268555,0.059387207,0.011779785,-0.05871582,-0.019317627,0.044952393,-0.045776367,-8.422136e-05,0.037841797,-0.019958496,-0.06530762,-0.0009217262,-0.03375244,0.00215148