INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('03493b4a-6a77-48c7-918b-7f64642d2f23', 'Food Systems Transformation Assessment Method', 'A diagnostic method for assessing the readiness and potential of food systems for transformation toward greater sustainability, resilience, and equity. Examines food system drivers, components, and outcomes at national and sub-national levels.', 'Provides a comprehensive diagnostic framework for understanding food system dynamics and identifying leverage points for transformation interventions.', 'Use when conducting food systems analyses for national food system pathway development or when designing transformative food system interventions.', 'Designed for policymakers, researchers, and development practitioners working on food systems transformation.', '{"Policy and Regulatory","Market Systems"}', '{"Agri-food Systems"}', 'Method', 'Theoretical and diagnostics', '{Policymaker,Researcher,"Government agencies","Civil Society and INGOs"}', '{Global,Africa,Asia}', '{"CGIAR Foresight Initiative",IFPRI}', '2023-01-01', 'https://cgspace.cgiar.org/food-systems-assessment', 'IFPRI', NULL, '[-0.029327393,0.017608643,0.02130127,-0.027297974,-0.01083374,-0.0006995201,0.0056266785,0.022338867,0.01878357,0.04626465,0.040039062,-0.052886963,-0.038879395,-0.07147217,-0.0035057068,-0.0019187927,0.030410767,-0.021972656,-0.032562256,0.015419006,0.024642944,-0.013954163,-0.01864624,0.025115967,0.028045654,-0.03164673,-0.032043457,0.02684021,-0.027572632,-0.021743774,0.02822876,-0.015960693,-0.03488159,-0.018829346,0.023666382,0.01725769,-0.044708252,0.025894165,0.035217285,-0.012825012,-0.028717041,0.05038452,-0.02180481,0.004562378,0.010093689,-0.0282135