INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('c6ae2a8a-94e8-4ce1-b1f4-f6f22660c3fc', 'Regenerative Agriculture Transition Framework', 'A conceptual framework for guiding the transition from conventional to regenerative agriculture practices at farm and landscape levels. Defines transition stages, principles, and monitoring indicators for regenerative agricultural systems.', 'Provides a stage-based transition model for regenerative agriculture with clear principles, practices, and monitoring indicators for each transition stage.', 'Use when designing regenerative agriculture programs or developing policies to support the transition from conventional to regenerative farming.', 'Designed for researchers, policymakers, and extension services interested in regenerative agriculture transitions.', '{"Policy and Regulatory","Monitoring, Evaluation and Learning"}', '{"Climate Resilience","Agri-food Systems"}', 'Framework', 'Conceptual', '{Researcher,Policymaker,"Extension services","Farmers and Agro-pastoralists"}', '{Global,Europe,"Latin America"}', '{"Alliance of Bioversity International and CIAT","Wageningen University"}', '2024-01-01', 'https://cgspace.cgiar.org/regenerative-ag-framework', 'Alliance of Bioversity-CIAT', NULL, '[-0.016937256,0.03363037,0.034851074,-0.012817383,-0.028793335,-0.0184021,0.013160706,0.017471313,0.022247314,0.052093506,0.033081055,0.0064315796,-0.027038574,-0.02494812,0.001950264,-0.012863159,0.026504517,-0.002313614,0.0038795471,0.06878662,0.0076408386,-0.024597168,-0.013221741,0.011108398,-0.0116119385,-0.03552246,-0.007007599,0.051635742,-0.023910522,-0.018997192,0.01008606,-0.02772522,0.0065574646,-0.03277588,0.005302429,-0.029174805,0.00708770