INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('8e056b82-92c0-41ae-9158-cd203d0c72b6', 'One Health Approach for Agricultural Systems', 'A conceptual framework integrating human health, animal health, and environmental health perspectives into agricultural systems analysis and intervention design. Addresses antimicrobial resistance, zoonotic disease risks, and pesticide exposure in agricultural contexts.', 'Provides an integrated analytical framework for identifying and managing health risks at the human-animal-environment interface in agricultural systems.', 'Use when designing agricultural programs that need to consider health outcomes or when assessing health risks in agricultural value chains.', 'Designed for researchers, policymakers, and development practitioners working at the agriculture-health nexus.', '{"Policy and Regulatory"}', '{"Agri-food Systems"}', 'Framework', 'Conceptual', '{Researcher,Policymaker,"Government agencies","Humanitarian assistance practitioners"}', '{Global,Asia,Africa}', '{"ILRI One Health Program",WHO,FAO}', '2023-01-01', 'https://cgspace.cgiar.org/one-health-agriculture', 'ILRI', NULL, '[-0.019378662,0.020126343,0.04940796,0.04574585,-0.056793213,-0.019485474,0.025985718,0.036834717,0.01876831,0.028869629,0.016082764,-0.011497498,-0.022888184,-0.025543213,-0.009361267,-0.03527832,0.02418518,-0.013496399,0.009986877,0.043945312,0.027420044,0.04244995,0.012023926,0.016586304,-0.041290283,-0.06756592,0.016662598,0.022491455,-0.017593384,-0.01687622,0.033935547,-0.027389526,0.006629944,0.008361816,-0.014656067,-0.009422302,-0.0317688,0.009529114,0.017349243,0.07067871,0.01979065,0.023590088,0.023773193,0.028717041,-0.015235901,-0.013046265,-0.0