INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('c5b7e601-a758-4500-a367-ee9014b43eb6', 'Sustainable Land Management Decision Brief', 'A policy brief format tool summarizing evidence on sustainable land management practices for drylands, including conservation agriculture, agroforestry, and water harvesting. Presents cost-benefit analysis and adoption barriers for policymakers.', 'Synthesizes evidence on sustainable land management options and presents cost-benefit comparisons to inform policy decisions on land management investments.', 'Use when briefing policymakers on sustainable land management options or when making investment cases for land restoration programs.', 'Designed for policymakers, government agencies, and funders making decisions about land management investments.', '{"Policy and Regulatory"}', '{"Climate Resilience","Agri-food Systems"}', 'Brief', 'Established and field-tested', '{Policymaker,"Government agencies","Funders and Donors"}', '{Africa,MENA,"Central and West Asia and North Africa (CWANA)"}', '{"ICARDA Land Management","GIZ Soil Protection"}', '2020-01-01', 'https://cgspace.cgiar.org/slm-decision-brief', 'ICARDA', NULL, '[0.014778137,0.026260376,0.041015625,0.008934021,-0.028289795,0.03555298,0.00365448,0.022277832,0.033599854,0.06567383,0.030838013,-0.006164551,-0.021224976,-0.033355713,0.050048828,-0.0014820099,-0.008911133,-0.013580322,-0.0085372925,0.021911621,0.02583313,0.046569824,-0.011619568,0.039978027,0.016586304,-0.037200928,-0.029174805,-0.012649536,0.0063552856,-0.010154724,0.036193848,-0.019500732,-0.0129776,-0.0146102905,0.0029640198,0.033599854,0.009796143,-0.030059814,0.035461426,0.014404297,-0.033966064,-0.009536743,-0.021224976