INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('90feb374-a89b-4dd1-8169-f8dde39005ef', 'Scaling Readiness Assessment', 'The Scaling Readiness Assessment provides a rapid yet rigorous methodology for determining whether an agricultural innovation and its surrounding enabling environment are ready for scaling investments. It helps funders, governments, and implementing organizations make evidence-based decisions about when and how to scale. Scaling Readiness synthesizes evidence across five readiness dimensions: technical maturity, demand validation, business model viability, enabling environment fitness, and organizational capacity. This integrated approach prevents premature scaling of innovations that lack the necessary foundations for sustainable growth.', 'Five-dimension readiness framework from technical maturity to enabling environment fitness; Rapid assessment protocol completable in 2-3 days with available data; Readiness scoring dashboard with visual profile output; Decision framework for scaling investment prioritization', 'Identify the innovation to be assessed and assemble a multidisciplinary assessment team. Collect and review available evidence for each of the five readiness dimensions. Score each dimension using the standardized rubrics and evidence requirements.', 'Designed for funders and investors working in agricultural development.', '{"Policy and Regulatory","Monitoring, Evaluation and Learning"}', '{"Scaling Innovation"}', 'Method', 'Established and field-tested', '{"Development Practitioner","Government agencies","Monitoring and Evaluation specialists",Policymaker}', '{Africa,Asia,"Latin America"}', '{"Marc Schut","Cees Leeuwis","Wageningen University