INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('531e6155-5e64-41b6-bea6-e7384da718ba', 'Participatory Varietal Selection Methodology', 'A methodology for involving farmers directly in crop variety selection and testing processes to ensure that released varieties match farmer preferences and local growing conditions. Covers trial design, farmer evaluation protocols, and feedback integration into breeding programs.', 'Provides protocols for designing and managing participatory variety trials with farmer panels, including evaluation criteria, scoring methods, and data analysis procedures.', 'Use during the variety evaluation and release stages of crop breeding programs to ensure farmer preferences inform variety selection decisions.', 'Designed for plant breeders, researchers, and extension services involved in crop improvement programs.', '{"Gender Equality and Social Inclusion"}', '{"Agri-food Systems","Scaling Innovation"}', 'Method', 'Established and field-tested', '{Researcher,"Extension services","Farmers and Agro-pastoralists","Development Practitioner"}', '{Global,Africa,Asia}', '{"CIMMYT Breeding Program","IRRI Social Sciences"}', '2017-01-01', 'https://cgspace.cgiar.org/pvs-methodology', 'CIMMYT', NULL, '[-0.002521515,-0.0073242188,0.038879395,-0.0011396408,-0.05682373,-0.024002075,0.043945312,-0.015052795,0.025360107,0.07208252,0.02017212,-0.03274536,-0.010391235,-0.018463135,-0.016662598,-0.06500244,0.018234253,0.039398193,-0.016021729,-0.0025863647,0.05090332,0.058044434,0.00415802,0.030654907,0.005809784,-0.04901123,0.0030117035,0.06964111,-0.0052223206,-0.07293701,-0.022857666,-0.016860962,-0.05505371,-0.032440186,-0.059692383,0.002166748,0.024642944,0.00955963