INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('24c8f29e-d552-4f4c-8efb-c2dc2506e5c0', 'Nutrition-Sensitive Irrigation Toolkit', 'A toolkit integrating nutrition objectives into irrigation program design and management. Addresses how irrigation investments can maximize nutrition outcomes through dietary diversification, homestead food production, and gender-equitable water access.', 'Provides design guidance and monitoring tools for ensuring that irrigation investments contribute to improved nutrition outcomes alongside agricultural productivity gains.', 'Use when designing irrigation programs to ensure they contribute to nutrition objectives and equitable water access.', 'Designed for irrigation scheme managers, development practitioners, and government agencies planning irrigation investments.', '{"Gender Equality and Social Inclusion","Policy and Regulatory"}', '{"Agri-food Systems","Climate Resilience"}', 'Toolkit', 'Conceptual', '{"Irrigation scheme managers","Development Practitioner","Government agencies","Farmers and Agro-pastoralists"}', '{Asia,Africa,"Low-income and middle-income countries"}', '{"IWMI Nutrition-Water Nexus Team",IFPRI}', '2023-01-01', 'https://cgspace.cgiar.org/nutrition-irrigation-toolkit', 'IWMI', NULL, '[-0.009391785,0.01826477,0.011428833,2.1755695e-05,-0.010597229,-0.0181427,0.062805176,0.052825928,0.015975952,0.011932373,0.0052375793,-0.0018386841,-0.022583008,-0.062438965,0.04260254,-0.0049438477,0.022323608,-0.009048462,-0.02835083,0.061065674,0.039398193,0.04724121,0.012527466,0.011795044,0.041046143,-0.012481689,-0.025131226,0.06964111,0.012702942,-0.013916016,0.017730713,-0.010932922,-0.06286621,-0.040740967,0.01600647,-0.014381409,0.0