INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('e0b0aede-d1ab-4b3d-ba18-231090a5fe43', 'Policy Landscape Mapping Tool', 'Policy Landscape Mapping is a systematic method for identifying, analyzing, and visualizing the full range of policies, regulations, and institutional arrangements that shape the enabling environment for agricultural innovation. The method combines desk-based policy analysis with stakeholder consultations to produce comprehensive maps of the policy ecosystem. These maps reveal both opportunities and constraints, helping teams develop targeted advocacy and engagement strategies.', 'Comprehensive policy inventory covering regulations, strategies, and institutional mandates; Stakeholder mapping to identify key influencers and decision-makers; Gap analysis methodology for identifying policy bottlenecks; Visual policy map tool for communicating complex policy landscapes', 'Define the scope of the policy landscape analysis, including geographic boundaries and innovation focus. Conduct a systematic review of existing policies, regulations, and institutional frameworks. Map key stakeholders and their roles, interests, and influence in the policy process.', 'Designed for policymakers working in agricultural development.', '{"Policy and Regulatory"}', '{"Agri-food Systems"}', 'Method', 'Established and field-tested', '{"Development Practitioner","Government agencies",Policymaker}', '{Africa}', '{"IFAD Policy Division","CGIAR Research Program on Policies, Institutions and Markets"}', '2017-01-01', 'https://www.ifad.org/policy-landscape', 'IFAD', NULL, '[-0.008644104,0.003622055,0.033325195,-0.0046920776,-0.017288208,0.015274048,0.014450073,-0.036468506,-0.003213882