INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('286226a6-887f-458b-b055-d2524d2d95c7', 'Digital Agriculture Assessment Tool', 'The Digital Agriculture Assessment Tool (DAAT) provides a comprehensive framework for evaluating the digital infrastructure landscape and identifying high-value opportunities for digital agricultural services in developing country contexts. As digital technologies increasingly shape agricultural systems, the DAAT helps governments, development organizations, and private sector actors understand the current state of digital readiness across connectivity, devices, digital literacy, data governance, and regulatory dimensions.', 'Five-dimension readiness assessment covering connectivity, devices, literacy, data, and regulation; Country benchmarking and comparison dashboard; Investment prioritization matrix for digital agriculture infrastructure; Policy gap analysis for digital agricultural services regulation', 'Collect baseline data using the DAAT data collection toolkit and secondary data sources. Score each of the five dimensions using the standardized scoring guide. Generate the Digital Agriculture Readiness Index and dimension profiles.', 'Designed for development practitioners, researchers working in agricultural development.', '{"Digital and Financial Services","Market Systems"}', '{"Scaling Innovation"}', 'Tool', 'Prototype', '{Agribusiness,"Development Practitioner","Private sector entities","Project and program managers"}', '{Africa,Asia}', '{"World Bank Digital Development",CTA}', '2021-01-01', 'https://www.worldbank.org/digital-agriculture', 'World Bank', NULL, '[-0.012962341,0.01789856,0.037902832,0.014274597,0.0025157928,0.02571106,0.0310