INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('32e3b3dd-3fbc-4bb5-a02b-2c0c09b7acf8', 'Innovation Scaling Readiness Assessment', 'The Innovation Scaling Readiness Assessment (ISRA) provides a rapid yet rigorous methodology for determining whether an agricultural innovation and its surrounding enabling environment are ready for scaling investments. ISRA synthesizes evidence across five readiness dimensions: technical maturity, demand validation, business model viability, enabling environment fitness, and organizational capacity.', 'Five-dimension readiness framework from technical maturity to enabling environment fitness; Rapid assessment protocol completable in 2-3 days with available data; Readiness scoring dashboard with visual profile output; Decision framework for scaling investment prioritization', 'Identify the innovation to be assessed and assemble a multidisciplinary assessment team. Collect and review available evidence for each of the five readiness dimensions. Score each dimension using the standardized rubrics and evidence requirements.', 'Designed for development practitioners, researchers working in agricultural development.', '{"Policy and Regulatory","Monitoring, Evaluation and Learning"}', '{"Scaling Innovation"}', 'Method', 'Prototype', '{"Development Practitioner","Government agencies","Monitoring and Evaluation specialists",Policymaker}', '{Africa,Asia,"Latin America"}', '{"CGIAR Research Program on Policies, Institutions and Markets"}', '2021-01-01', 'https://cgspace.cgiar.org/innovation-readiness', 'CG Space', NULL, '[0.0043945312,0.048431396,0.05706787,-0.012458801,-0.024810791,-0.016952515,0.01763916,-0.017501831,0.016036987,0.051361084,-0.01687622