INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('016f580b-3b4f-4407-a8f7-5f11e97d43ea', 'Nutrition-Sensitive Agriculture Framework', 'The Nutrition-Sensitive Agriculture Framework provides guidance for designing agricultural interventions that explicitly contribute to improved nutrition outcomes. It bridges the gap between agricultural production and human nutrition by identifying pathways through which agriculture can improve dietary diversity, food safety, and nutrition security. The framework identifies six agricultural-nutrition pathways: food production for own consumption, agricultural income for food purchasing, food prices and market access, women''s empowerment and time use, natural resource management, and food safety and quality.', 'Six agricultural-nutrition pathway analysis framework; Nutrition-sensitive intervention design templates; Dietary diversity assessment tools for baseline and endline measurement; Integration guide for nutrition indicators in agricultural M&E systems', 'Conduct a nutrition situation analysis in the target area using the diagnostic toolkit. Map the six agricultural-nutrition pathways and identify the most relevant for the context. Design interventions that address identified pathway gaps using the design templates.', 'Designed for funders and investors working in agricultural development.', '{"Gender Equality and Social Inclusion","Market Systems"}', '{"Agri-food Systems"}', 'Framework', 'Established and field-tested', '{Agribusiness,"Development Practitioner",Researcher}', '{Asia,Africa}', '{IFAD,"FAO Nutrition Division",A4NH}', '2017-01-01', 'https://www.ifad.org/nutrition-sensitive', 'IFAD', NULL, '[-0.022598267,0.037750244,0.0415954