INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('12f1bbc5-9153-4017-8e31-c859bfa7630d', 'Agricultural Finance Readiness Tool', 'The Agricultural Finance Readiness Tool (AFRT) helps governments, financial institutions, and development partners assess the enabling conditions for agricultural financial services, including traditional lending, digital finance, agricultural insurance, and warehouse receipt systems. The tool evaluates five dimensions of agricultural finance readiness: regulatory environment, financial infrastructure, institutional capacity, market development, and farmer financial literacy. Each dimension is scored using standardized indicators.', 'Five-dimension agricultural finance readiness assessment; Regulatory environment analysis for agricultural lending and insurance; Financial infrastructure gap assessment including digital payment systems; Farmer financial literacy diagnostic tools', 'Define the scope of the assessment including geographic coverage and financial service types. Collect data on each of the five readiness dimensions using the standardized questionnaires. Score each dimension and calculate the Agricultural Finance Readiness Index.', 'Designed for development practitioners, funders and investors working in agricultural development.', '{"Monitoring, Evaluation and Learning","Digital and Financial Services"}', '{"Scaling Innovation","Agri-food Systems"}', 'Tool', 'Prototype', '{"Development Practitioner","Monitoring and Evaluation specialists","Private sector entities","Project and program managers"}', '{Africa,Asia}', '{"World Bank Agriculture Finance Unit",CGAP}', '2022-01-01', 'https://www.worldbank.org/ag-finance-readiness', 'World Bank', 