INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('c32c5de1-4b78-4fb4-aecb-5acc96fa612c', 'Agroecology Transition Scorecard', 'The Agroecology Transition Scorecard provides a standardized methodology for measuring the extent to which farming systems are adopting agroecological principles, including biodiversity enhancement, soil health management, nutrient cycling, and integration of crop-livestock systems. The scorecard assesses ten agroecological elements: diversity, synergies, efficiency, resilience, recycling, co-creation of knowledge, human and social values, culture and food traditions, responsible governance, and circular and solidarity economy.', 'Ten-element agroecological assessment framework aligned with FAO principles; Standardized scoring rubrics for quantitative comparison; Spider diagram visualization for communication with stakeholders; Policy relevance analysis for supporting agroecological transitions', 'Select the assessment unit (farm, community, or landscape) and scope. Train assessors in the ten agroecological elements and scoring rubrics. Conduct farm-level assessments using participatory methods with farmers.', 'Designed for policymakers working in agricultural development.', '{"Policy and Regulatory"}', '{"Climate Resilience","Agri-food Systems"}', 'Scorecard', 'Prototype', '{"Government agencies",Policymaker,"Project and program managers"}', '{Asia,Africa,"Latin America"}', '{"FAO Agroecology Unit","Alliance of Bioversity International and CIAT"}', '2022-01-01', 'https://www.fao.org/agroecology/scorecard', 'FAO', NULL, '[0.014076233,0.01576233,0.050750732,0.017990112,-0.016601562,0.01574707,0.016021729,-0.029174805,0.017562866,0.00039100647,-0.011848