INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('151e1ee3-b026-459d-b58b-6bd1bb0c56dc', 'Agricultural Knowledge and Innovation Systems (AKIS) Toolkit', 'The Agricultural Knowledge and Innovation Systems (AKIS) Toolkit provides a systems-level approach to understanding and strengthening the networks of actors, institutions, and processes that generate, share, and use agricultural knowledge and innovations. The toolkit moves beyond linear models of technology transfer to analyze the complex interactions between research, extension, education, farmer organizations, private sector, and policymakers that collectively determine how agricultural knowledge is created and used.', 'AKIS architecture mapping and analysis methodology; Knowledge flow assessment tools for identifying systemic bottlenecks; Stakeholder network analysis for understanding AKIS governance; Intervention design framework for AKIS strengthening', 'Define the AKIS scope including geographic, thematic, and institutional boundaries. Map the AKIS architecture including actors, functions, and linkages. Assess knowledge flow patterns and identify bottlenecks.', 'Designed for development practitioners, researchers working in agricultural development.', '{"Policy and Regulatory","Digital and Financial Services"}', '{"Scaling Innovation","Agri-food Systems"}', 'Framework', 'Prototype', '{"Development Practitioner","Government agencies",Policymaker,"Private sector entities"}', '{Africa,Asia}', '{FAO,"EU SCAR-AKIS Working Group"}', '2020-01-01', 'https://www.fao.org/akis-toolkit', 'FAO', NULL, '[-0.022445679,0.0012073517,0.0061149597,-0.023529053,-0.007419586,-0.0002002716,-0.003868103,-0.0024318695,-0.0075683594,0.0290527