INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('c1fa4cf1-641f-4a05-9909-07b2914a99c0', 'Agricultural Trade Policy Analyzer', 'The Agricultural Trade Policy Analyzer provides a comprehensive toolkit for assessing agricultural trade policies, including tariffs, non-tariff barriers, export restrictions, and regional trade agreements, and their impacts on food security, farmer incomes, and agricultural market development. The tool integrates quantitative trade analysis methods with qualitative assessment of policy implementation and institutional capacity, providing a complete picture of how trade policies affect agricultural systems.', 'Comprehensive trade policy inventory and analysis methodology; Tariff and non-tariff barrier assessment tools; Food security impact assessment framework for trade policy changes; Regional trade agreement evaluation methodology', 'Conduct a comprehensive inventory of agricultural trade policies. Analyze tariff structures and their impacts on agricultural competitiveness. Assess non-tariff barriers to agricultural trade.', 'Designed for policymakers working in agricultural development.', '{"Policy and Regulatory","Market Systems"}', '{"Agri-food Systems"}', 'Tool', 'Established and field-tested', '{Agribusiness,"Development Practitioner","Government agencies",Policymaker}', '{Africa,Asia,"Latin America"}', '{"IFPRI Trade and Institutions Division",IFAD}', '2020-01-01', 'https://www.ifad.org/trade-policy', 'IFAD', NULL, '[-0.03942871,0.019607544,0.022338867,-0.0049362183,-0.013954163,0.032836914,0.02482605,0.021484375,0.041900635,0.037017822,0.03186035,-0.014961243,-0.01309967,-0.047790527,-0.004573822,-0.038085938,-0.01625061,0.005420685,-0.0261