INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('871a789d-7a3a-400f-a1cc-1b4b3012b7d2', 'Farmer Field School Implementation Guide', 'The Farmer Field School (FFS) Implementation Guide provides comprehensive guidance for designing, implementing, and scaling farmer-led learning programs that build farmers'' capacity to analyze their production systems, identify problems, and test potential solutions. FFS is a group-based learning approach where farmers conduct season-long field experiments comparing different practices, make observations, analyze data, and make collective decisions about technology adoption based on their own evidence.', 'Season-long participatory learning curriculum design guide; Facilitator training program with competency framework; Monitoring and evaluation tools for FFS program assessment; Scaling strategy guide for institutionalizing FFS in extension systems', 'Assess the demand for FFS in the target area and identify priority topics. Select and train FFS facilitators using the competency-based training program. Design the FFS curriculum with season-long field experiments.', 'Designed for farming communities working in agricultural development.', '{"Gender Equality and Social Inclusion","Policy and Regulatory"}', '{"Scaling Innovation","Agri-food Systems"}', 'Method', 'Established and field-tested', '{"Development Practitioner","Government agencies",Policymaker,Researcher}', '{Africa,Asia}', '{"FAO Plant Production and Protection Division"}', '2016-01-01', 'https://www.fao.org/farmer-field-schools', 'FAO', NULL, '[-0.015342712,0.023651123,0.057647705,-0.03805542,-0.030136108,-0.027450562,0.024734497,-0.04071045,0.0036411285,0.050842285,0.02758789,-0.029