INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('77c6037a-921a-458e-b962-0a1f2dd5e2fa', 'Gender-Responsive Plant Breeding Method', 'The Gender-Responsive Plant Breeding Method provides a structured approach for integrating gender analysis into all stages of the plant breeding process, from priority setting and trait identification through variety testing and release. Traditional breeding programs often prioritize traits valued by male farmers and the commercial market, overlooking traits important to women farmers such as cooking quality, processing ease, storage characteristics, and nutritional content.', 'Gender-differentiated trait preference assessment tools; Participatory variety selection protocols with gender-disaggregated analysis; Gender-responsive variety release and dissemination strategies; Impact assessment methodology for gender-responsive breeding outcomes', 'Conduct gender-differentiated demand assessments in target populations. Integrate gender-relevant traits into breeding program priority setting. Design participatory variety selection trials with gender-disaggregated protocols.', 'Designed for farming communities working in agricultural development.', '{"Gender Equality and Social Inclusion"}', '{"Agri-food Systems","Scaling Innovation"}', 'Method', 'Prototype', '{"Development Practitioner",Researcher}', '{Africa,Asia}', '{"CGIAR Gender and Breeding Initiative","Hale Tufan","Cornell University"}', '2022-01-01', 'https://cgspace.cgiar.org/gender-breeding', 'CG Space', NULL, '[0.026168823,0.04333496,0.05307007,0.041778564,-0.023269653,-0.02520752,0.06744385,0.015914917,0.020309448,0.012008667,0.022537231,0.0010967255,0.015975952,-0.017913818,-0.03918457,-0