INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('c757c6ad-19ec-4e7f-82a7-26bd8ddde2df', 'Seed System Reform in East Africa', 'How policy reforms enabled improved seed varieties to reach 2 million smallholder farmers How policy reforms and institutional partnerships enabled improved seed varieties to reach 2 million smallholder farmers. Innovation type: Policy Reform.', 'In 2018, a coalition of CGIAR researchers, national agricultural research institutes, and civil society organizations embarked on a landmark effort to reform seed system policies across Kenya, Tanzania, and Uganda. The initiative recognized that despite years of investment in improved seed varieties, adoption remained low due to fragmented regulatory frameworks, inadequate quality assurance systems, and limited access to formal seed markets for smallholder farmers.', '47 improved varieties commercialized across three countries; 2 million smallholder farmers gained access to quality-assured seeds; Average yield increases of 35% for adopting households; Seed certification time reduced from 18 months to 6 months; Three countries adopted harmonized regional seed trade protocols', 'Multi-country reform processes require sustained investment in regional coordination mechanisms. Private sector engagement from the early stages of policy reform is critical for commercial viability. National seed policy reforms are insufficient without investments in quality assurance infrastructure. Women farmers benefit disproportionately when seed access reform is combined with gender-responsive extension.', '{"Policy and Regulatory","Market Systems"}', '{"Agri-food Systems","Scaling Innovation"}', 'Brief', 'Established and field-t