INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('cfc0d945-9cb4-4c4f-9bc5-abcd34a5eb6b', 'Soil Health Monitoring in East Africa', 'Establishing national soil testing infrastructure to support evidence-based farming decisions Establishing national soil testing infrastructure to support evidence-based farming decisions. Innovation type: Digital Monitoring.', 'Soil degradation affects over 40% of agricultural land in East Africa, yet most smallholder farmers lack access to reliable information about soil health. A multi-year initiative developed the enabling environment for a national soil health monitoring network in Ethiopia.', '42 functioning soil testing laboratories with standardized protocols; Digital soil health platform with 200,000+ soil sample records; Community promoter network reaching 100,000+ farming households; Average 25% reduction in fertilizer waste among participating farmers; National soil testing policy framework adopted by government', 'National soil health systems require a coordinating institution with sufficient authority. Community-level promoters are critical for translating lab results into actionable advice. Digital platforms dramatically increase the value of soil testing investments. Commercial laboratories require clear quality standards and incentives.', '{"Monitoring, Evaluation and Learning","Digital and Financial Services"}', '{"Agri-food Systems"}', 'Brief', 'Established and field-tested', '{"Development Practitioner","Monitoring and Evaluation specialists","Private sector entities",Researcher}', '{Africa}', '{"Alliance of Bioversity-CIAT Soils Team","Ethiopian Institute of Agricultural Research"}', '2023-01-01', '', 'Alliance of Bioversity-