INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('1d067b36-de90-436e-ab69-5c42541741ff', 'Irrigation Governance Reform in South Asia', 'Reforming water management institutions to improve equity and efficiency in irrigation systems Reforming water management institutions to improve equity and efficiency in irrigation systems. Innovation type: Institutional Reform.', 'Across South Asia, irrigation systems serve millions of farming households but are often plagued by inequitable water distribution, deteriorating infrastructure, and weak governance. IWMI led a multi-country initiative to reform irrigation governance in India, Nepal, and Bangladesh, focusing on strengthening water user associations, improving water allocation systems, and building institutional capacity.', '1.5 million farming households benefiting from improved water distribution; 60% reduction in water conflicts in target areas; Water use efficiency improved by 25% in reformed irrigation systems; Women''s participation in water user associations increased from 10% to 35%; Sustainable financing mechanisms established in three countries', 'Irrigation governance reform requires sustained engagement over multiple years. Women''s participation in water governance leads to more equitable outcomes. Transparent water allocation systems reduce conflicts and improve trust. Sustainable financing is essential for maintaining governance reforms.', '{"Policy and Regulatory","Gender Equality and Social Inclusion"}', '{"Climate Resilience","Agri-food Systems"}', 'Brief', 'Established and field-tested', '{"Development Practitioner","Government agencies",Policymaker,Researcher}', '{Asia}', '{"IWMI South Asia","Mark Giordano"}', 