INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('9e236128-d96c-4733-a9e4-dc70bd528a00', 'Bio-Fertilizer Scaling in West Africa', 'Building regulatory and market systems for biological soil fertility products Building regulatory and market systems for biological soil fertility products. Innovation type: Market System Development.', 'West African soils are among the most depleted globally, yet access to soil fertility inputs remains limited for most smallholder farmers due to high costs and supply constraints. IITA led an initiative to scale bio-fertilizer products in Nigeria and Ghana by building the regulatory, quality assurance, and market systems needed for a functional bio-fertilizer industry.', 'Three bio-fertilizer products registered and commercialized; 100,000 farming households using bio-fertilizer products; 30% reduction in chemical fertilizer dependency among adopters; Bio-fertilizer quality testing laboratories established in two countries; 15 private sector bio-fertilizer enterprises supported', 'Quality assurance systems are foundational for building farmer trust in bio-fertilizers. Private sector engagement is essential for sustainable bio-fertilizer supply. Regulatory frameworks must balance rigor with accessibility for small enterprises. Farmer training programs need to demonstrate bio-fertilizer effectiveness in local conditions.', '{"Policy and Regulatory","Market Systems"}', '{"Agri-food Systems","Climate Resilience"}', 'Brief', 'Established and field-tested', '{Agribusiness,"Development Practitioner","Government agencies",Policymaker}', '{Africa}', '{"IITA Soil Health Program",N2Africa}', '2025-01-01', '', 'IITA', NULL, '[0.01953125,0.015426636,0.0535583