INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('34607db5-c962-4800-837d-3f4f9b599e1d', 'Inclusive Design Matrix for Agricultural Technologies', 'A matrix tool for evaluating whether agricultural technologies and services are designed to be accessible and beneficial to women, youth, people with disabilities, and other marginalized groups. Scores technologies across accessibility, affordability, cultural appropriateness, and safety dimensions.', 'Provides a structured scoring matrix that evaluates agricultural technologies against inclusion criteria, generating an inclusion score and improvement recommendations.', 'Apply during the design phase of agricultural technology development or when evaluating existing technologies for inclusion gaps.', 'Designed for development practitioners, researchers, and extension services working on technology dissemination.', '{"Gender Equality and Social Inclusion","Digital and Financial Services"}', '{"Scaling Innovation"}', 'Matrix', 'Prototype', '{"Development Practitioner",Researcher,"Extension services","Private sector entities"}', '{Global,Africa,Asia}', '{"CGIAR Gender Platform","CIMMYT Gender Team"}', '2022-01-01', 'https://cgspace.cgiar.org/inclusive-design-matrix', 'CGIAR Gender Platform', NULL, '[0.019714355,0.026794434,0.01789856,0.012008667,0.010925293,-0.0128479,0.043548584,-0.02394104,-0.0057525635,0.0140686035,-0.008621216,-0.016983032,-0.025375366,-0.024261475,0.020187378,-0.009529114,0.017349243,-0.05419922,-0.0020332336,0.012313843,0.03277588,0.041137695,-0.0054512024,0.037261963,0.0009403229,-0.046844482,0.0038471222,0.016296387,0.006175995,0.033569336,0.007659912,-0.013916016,-0.034851074,-0.013633728,0.034606934,-0.0151