INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('075cef3e-ed3d-4e88-bb39-5d1ef64be171', 'Contribution Analysis Framework for Agricultural Impact', 'A framework for assessing whether and how agricultural research and development interventions have contributed to observed changes. Uses a structured approach to build a credible contribution story through evidence gathering and alternative explanation testing.', 'Provides a six-step methodology for building credible contribution claims linking agricultural interventions to observed development outcomes.', 'Apply when rigorous experimental evaluation is not feasible but there is a need to assess whether programs contributed to observed outcomes.', 'Designed for evaluators, researchers, and program managers seeking to demonstrate program contributions to development outcomes.', '{"Monitoring, Evaluation and Learning"}', '{"Agri-food Systems"}', 'Framework', 'Established and field-tested', '{"Monitoring and Evaluation specialists",Researcher,"Funders and Donors"}', '{Global}', '{"John Mayne","CGIAR Standing Panel on Impact Assessment"}', '2018-01-01', 'https://cgspace.cgiar.org/contribution-analysis', 'CGIAR SPIA', NULL, '[0.0032424927,-0.006996155,-0.0016431808,0.017700195,-0.03086853,-0.013839722,0.005706787,0.039367676,0.011642456,0.034942627,0.02999878,-0.029388428,0.02218628,-0.0289917,-0.021194458,0.01689148,0.027420044,-0.0004413128,-0.012901306,0.051116943,0.023666382,0.03753662,0.008720398,0.01096344,0.02885437,-0.06652832,-0.05255127,0.029464722,-0.023147583,-0.05493164,0.015510559,0.0010490417,-0.029327393,-0.038909912,-0.024154663,0.0005097389,-0.03579712,-0.0016756058,0.046813965,0.031799316,0.028518677,0.059448242,5.