INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('89ebf4da-350c-4669-974c-177f7bd8af63', 'Behavioral Insights for Agricultural Technology Adoption', 'A theoretical framework applying behavioral economics insights to understand and promote agricultural technology adoption by smallholder farmers. Covers cognitive biases, social norms, default effects, and nudge interventions in agricultural contexts.', 'Provides a theoretical framework and practical toolkit for designing behaviorally-informed agricultural extension and technology promotion programs.', 'Use when designing technology adoption promotion strategies or when standard approaches have failed to achieve expected adoption rates.', 'Designed for researchers, extension services, and development practitioners seeking to improve technology uptake.', '{"Digital and Financial Services","Market Systems"}', '{"Scaling Innovation"}', 'Framework', 'Theoretical and diagnostics', '{Researcher,"Extension services","Development Practitioner","Project and program managers"}', '{Global,Africa,Asia}', '{"CIMMYT Adoption Studies","World Bank Behavioral Insights Team"}', '2022-01-01', 'https://cgspace.cgiar.org/behavioral-insights-ag', 'CIMMYT', NULL, '[-0.009208679,-0.010627747,-0.028335571,0.013397217,-0.014503479,-0.0033550262,0.027297974,0.05783081,-0.0039634705,0.010620117,0.019760132,-0.05239868,-0.0043144226,-0.0071640015,0.027801514,-0.010864258,0.030670166,-0.0385437,-0.024642944,0.05456543,0.032806396,0.05532837,0.025650024,0.036834717,-0.0030136108,-0.054595947,-0.018600464,0.02861023,-0.012435913,-0.01612854,0.021591187,-0.02281189,-0.0418396,-0.0501709,-0.016693115,-0.019485474,-0.0027332306,-0.027114868,0.04034424,0.03915405