INSERT INTO public.tools (id, title, summary, what_it_does, when_to_use_it, who_its_for, pillars, domains, type, stage, target_users, geography, authors, date_published, source_url, source_organization, cover_image_url, embedding, average_rating, rating_count, view_count, cgspace_id, relevance_score, is_visible, created_at, updated_at) VALUES ('65624bba-715b-48ef-86ba-7dd5c8fde6bb', 'Digital Literacy Assessment for Rural Communities', 'A diagnostic tool for assessing digital literacy levels in rural farming communities, covering device familiarity, internet usage, digital financial services, and information evaluation skills. Generates targeted training recommendations.', 'Assesses digital literacy across four domains and generates community-level digital literacy profiles with tailored training program recommendations.', 'Use before deploying digital agricultural services or when designing digital literacy training programs for rural communities.', 'Designed for extension services, development practitioners, and digital service providers working in rural areas.', '{"Digital and Financial Services","Gender Equality and Social Inclusion"}', '{"Scaling Innovation"}', 'Tool', 'Prototype', '{"Extension services","Development Practitioner","Local communities","Private sector entities"}', '{Africa,Asia,"Low-income and middle-income countries"}', '{"CTA Digital4Agriculture","GSMA Connected Women"}', '2022-01-01', 'https://cgspace.cgiar.org/digital-literacy-assessment', 'CTA', NULL, '[0.0090408325,0.039123535,0.032287598,0.013442993,0.027740479,-0.0038547516,0.022018433,0.03265381,0.018447876,0.05441284,-0.022521973,-0.06665039,-0.020309448,-0.038269043,0.027389526,0.006477356,0.0030460358,-0.0020446777,-0.008857727,0.080200195,0.08605957,0.009101868,0.016281128,-0.024429321,0.013137817,-0.025680542,-0.017669678,-0.0040359497,-0.020767212,-0.034118652,-0.03881836,-0.027664185,-0.03491211,-0.03918457,0.038360596,0.0023860931,-0.012420654,0.021575928,0.028518677,-0.005508423,